var QUESTIONS_THEORY_10 = [
// ==========================================
// EASY: 28 MCQs
// ==========================================
{type:"mcq",diff:"easy",en:{q:"What is a Computer Network?",opts:["A single computer working without internet","A group of interconnected computers sharing resources","A software used to type documents","A piece of hardware inside the CPU"],ans:1,exp:"A computer network is a system of interconnected computing devices, servers, and other hardware components. It allows sharing of resources like printers, files, and internet connections across the nodes. Networks use communication protocols to transmit data securely and efficiently."},hi:{q:"कंप्यूटर नेटवर्क (Computer Network) क्या है?",opts:["बिना इंटरनेट के काम करने वाला अकेला कंप्यूटर","संसाधनों को साझा करने वाले इंटरकनेक्टेड कंप्यूटरों का एक समूह","दस्तावेज़ टाइप करने के लिए उपयोग किया जाने वाला एक सॉफ्टवेयर","CPU के अंदर एक हार्डवेयर"],ans:1,exp:"कंप्यूटर नेटवर्क इंटरकनेक्टेड कंप्यूटिंग उपकरणों, सर्वर और अन्य हार्डवेयर घटकों की एक प्रणाली है। यह नोड्स में प्रिंटर, फाइल और इंटरनेट कनेक्शन जैसे संसाधनों को साझा करने की अनुमति देता है। नेटवर्क डेटा को सुरक्षित रूप से प्रसारित करने के लिए संचार प्रोटोकॉल का उपयोग करते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following describes a LAN (Local Area Network)?",opts:["Spans across multiple countries","Connects computers within a single building or campus","Used only for connecting mobile phones wirelessly","Provides global internet access via satellites"],ans:1,exp:"LAN (Local Area Network) is a network restricted to a relatively small geographic area, such as an office building, school, or home. It typically provides high data transfer speeds and uses technologies like Ethernet and Wi-Fi to interconnect local devices securely."},hi:{q:"निम्नलिखित में से कौन सा LAN (Local Area Network) का वर्णन करता है?",opts:["कई देशों में फैला हुआ नेटवर्क","एक ही इमारत या परिसर के भीतर कंप्यूटर को जोड़ता है","केवल मोबाइल फोन को वायरलेस तरीके से जोड़ने के लिए उपयोग किया जाता है","उपग्रहों के माध्यम से वैश्विक इंटरनेट पहुंच प्रदान करता है"],ans:1,exp:"LAN (लोकल एरिया नेटवर्क) एक ऐसा नेटवर्क है जो अपेक्षाकृत छोटे भौगोलिक क्षेत्र जैसे कार्यालय भवन, स्कूल या घर तक सीमित है। यह उच्च डेटा ट्रांसफर गति प्रदान करता है और स्थानीय उपकरणों को सुरक्षित रूप से जोड़ने के लिए ईथरनेट और वाई-फाई जैसी तकनीकों का उपयोग करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which physical network topology connects all devices to a single central cable?",opts:["Star Topology","Ring Topology","Bus Topology","Mesh Topology"],ans:2,exp:"In a Bus Topology, all network devices are connected to a single central cable known as the 'bus' or 'backbone'. Terminators are placed at both ends of this cable to absorb signals and prevent signal reflection. If the main backbone fails, the entire network drops."},hi:{q:"कौन सी भौतिक नेटवर्क टोपोलॉजी सभी उपकरणों को एक ही केंद्रीय केबल (central cable) से जोड़ती है?",opts:["स्टार टोपोलॉजी (Star Topology)","रिंग टोपोलॉजी (Ring Topology)","बस टोपोलॉजी (Bus Topology)","मेश टोपोलॉजी (Mesh Topology)"],ans:2,exp:"बस टोपोलॉजी में, सभी नेटवर्क डिवाइस एक केंद्रीय केबल से जुड़े होते हैं जिसे 'बस' या 'बैकबोन' कहा जाता है। संकेतों को अवशोषित करने और सिग्नल प्रतिबिंब को रोकने के लिए इस केबल के दोनों सिरों पर टर्मिनेटर लगाए जाते हैं। मुख्य बैकबोन विफल होने पर पूरा नेटवर्क गिर जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which network topology connects every node to exactly two other nodes, forming a continuous circular pathway?",opts:["Star","Bus","Ring","Tree"],ans:2,exp:"A Ring Topology forms a closed loop where each device is connected to two neighboring devices. Data travels in one direction (unidirectional) or both (bidirectional) passing through each node. Token passing mechanisms are often used to prevent data collisions in this topology."},hi:{q:"कौन सी नेटवर्क टोपोलॉजी प्रत्येक नोड को ठीक दो अन्य नोड्स से जोड़ती है, जिससे एक निरंतर वृत्ताकार मार्ग बनता है?",opts:["स्टार (Star)","बस (Bus)","रिंग (Ring)","ट्री (Tree)"],ans:2,exp:"एक रिंग टोपोलॉजी एक बंद लूप बनाती है जहां प्रत्येक डिवाइस दो पड़ोसी उपकरणों से जुड़ा होता है। डेटा प्रत्येक नोड से गुजरते हुए एक दिशा (यूनिडायरेक्शनल) या दोनों (द्विदिश) में यात्रा करता है। इस टोपोलॉजी में डेटा टकराव को रोकने के लिए अक्सर टोकन पासिंग तंत्र का उपयोग किया जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the full form of MAC Address in networking?",opts:["Media Access Control Address","Machine Authorization Code Address","Main Access Computer Address","Micro Application Control Address"],ans:0,exp:"MAC stands for Media Access Control. It is a unique 48-bit physical address embedded on the Network Interface Card (NIC) by the manufacturer. It operates at the Data Link Layer of the OSI model and ensures physical device identification on a local network."},hi:{q:"नेटवर्किंग में MAC एड्रेस का पूर्ण रूप क्या है?",opts:["मीडिया एक्सेस कंट्रोल एड्रेस (Media Access Control Address)","मशीन ऑथराइजेशन कोड एड्रेस","मेन एक्सेस कंप्यूटर एड्रेस","माइक्रो एप्लीकेशन कंट्रोल एड्रेस"],ans:0,exp:"MAC का अर्थ मीडिया एक्सेस कंट्रोल है। यह निर्माता द्वारा नेटवर्क इंटरफ़ेस कार्ड (NIC) पर एम्बेडेड एक अद्वितीय 48-बिट भौतिक पता है। यह OSI मॉडल की डेटा लिंक लेयर पर काम करता है और स्थानीय नेटवर्क पर भौतिक डिवाइस पहचान सुनिश्चित करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which basic networking device is considered 'dumb' because it broadcasts data to all connected ports without inspecting MAC addresses?",opts:["Switch","Router","Hub","Gateway"],ans:2,exp:"A Hub is a Layer 1 (Physical layer) device that acts as a multi-port repeater. It lacks the intelligence to inspect MAC addresses. When it receives a data frame on one port, it blindly broadcasts copies of that frame out to all other connected ports, creating high collision risks."},hi:{q:"किस बुनियादी नेटवर्किंग डिवाइस को 'डंब' (dumb) माना जाता है क्योंकि यह MAC एड्रेस का निरीक्षण किए बिना सभी कनेक्टेड पोर्ट पर डेटा प्रसारित (broadcast) करता है?",opts:["स्विच (Switch)","राउटर (Router)","हब (Hub)","गेटवे (Gateway)"],ans:2,exp:"हब एक लेयर 1 (फिजिकल लेयर) डिवाइस है जो मल्टी-पोर्ट रिपीटर के रूप में कार्य करता है। इसमें MAC एड्रेस का निरीक्षण करने की बुद्धि का अभाव होता है। जब यह एक पोर्ट पर डेटा फ्रेम प्राप्त करता है, तो यह उस फ्रेम की प्रतियां सभी जुड़े पोर्ट्स पर भेजता है, जिससे टकराव का जोखिम बढ़ता है।"}},
{type:"mcq",diff:"easy",en:{q:"What does IP stand for in the context of the Internet?",opts:["Internal Protocol","Internet Protocol","Intranet Procedure","Information Path"],ans:1,exp:"IP stands for Internet Protocol. It is the principal communications protocol in the Internet protocol suite for relaying datagrams across network boundaries. Its routing function enables internetworking, and it is responsible for logical addressing (IPv4 and IPv6)."},hi:{q:"इंटरनेट के संदर्भ में IP का क्या अर्थ है?",opts:["इंटरनल प्रोटोकॉल (Internal Protocol)","इंटरनेट प्रोटोकॉल (Internet Protocol)","इंट्रानेट प्रोसीजर (Intranet Procedure)","इन्फॉर्मेशन पाथ (Information Path)"],ans:1,exp:"IP का अर्थ इंटरनेट प्रोटोकॉल है। यह नेटवर्क सीमाओं के पार डेटाग्राम रिले करने के लिए इंटरनेट प्रोटोकॉल सूट में प्रमुख संचार प्रोटोकॉल है। इसका राउटिंग फ़ंक्शन इंटरनेटवर्किंग को सक्षम बनाता है, और यह तार्किक एड्रेसिंग (IPv4 और IPv6) के लिए जिम्मेदार है।"}},
{type:"mcq",diff:"easy",en:{q:"Which hardware device is fundamentally required to modulate analog signals to digital and demodulate digital to analog for internet over telephone lines?",opts:["Router","Switch","Modem","Hub"],ans:2,exp:"A Modem (Modulator-Demodulator) bridges the gap between digital computer signals and analog transmission lines (like DSL or dial-up telephone wires). It modulates digital data into analog waves for transmission and demodulates incoming analog waves back into digital data."},hi:{q:"टेलीफोन लाइनों पर इंटरनेट के लिए एनालॉग सिग्नल को डिजिटल में और डिजिटल को एनालॉग में बदलने के लिए किस हार्डवेयर डिवाइस की आवश्यकता होती है?",opts:["राउटर (Router)","स्विच (Switch)","मॉडेम (Modem)","हब (Hub)"],ans:2,exp:"एक मॉडेम (मोडुलेटर-डीमोडुलेटर) डिजिटल कंप्यूटर सिग्नल और एनालॉग ट्रांसमिशन लाइनों के बीच अंतर को पाटता है। यह ट्रांसमिशन के लिए डिजिटल डेटा को एनालॉग तरंगों में संशोधित करता है और आने वाली एनालॉग तरंगों को वापस डिजिटल डेटा में डीमॉड्यूलेट करता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the full form of WWW?",opts:["World Wide Web","World Web Wireless","Wide World Web","Web World Wide"],ans:0,exp:"WWW stands for World Wide Web. Invented by Tim Berners-Lee, it is an information system where documents and other web resources are identified by URLs, interlinked by hypertext links, and can be accessed via the Internet using a web browser."},hi:{q:"WWW का पूर्ण रूप क्या है?",opts:["वर्ल्ड वाइड वेब (World Wide Web)","वर्ल्ड वेब वायरलेस","वाइड वर्ल्ड वेब","वेब वर्ल्ड वाइड"],ans:0,exp:"WWW का अर्थ वर्ल्ड वाइड वेब है। टिम बर्नर्स-ली द्वारा आविष्कृत, यह एक सूचना प्रणाली है जहां दस्तावेजों और अन्य वेब संसाधनों को URL द्वारा पहचाना जाता है, हाइपरटेक्स्ट लिंक द्वारा इंटरलिंक किया जाता है, और वेब ब्राउज़र का उपयोग करके इंटरनेट के माध्यम से एक्सेस किया जा सकता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following is an example of a Web Browser?",opts:["Google","Google Chrome","Yahoo","Bing"],ans:1,exp:"Google Chrome is a software application (Web Browser) used to render HTML pages and navigate the World Wide Web. Conversely, Google, Yahoo, and Bing are Search Engines (web-based tools) that run inside a web browser to index and search the internet."},hi:{q:"निम्नलिखित में से कौन वेब ब्राउज़र का एक उदाहरण है?",opts:["Google","Google Chrome","Yahoo","Bing"],ans:1,exp:"Google Chrome एक सॉफ्टवेयर एप्लिकेशन (वेब ब्राउज़र) है जिसका उपयोग HTML पृष्ठों को प्रस्तुत करने और वर्ल्ड वाइड वेब पर नेविगेट करने के लिए किया जाता है। इसके विपरीत, Google, Yahoo और Bing सर्च इंजन हैं जो इंटरनेट खोजने के लिए वेब ब्राउज़र के अंदर चलते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which protocol is primarily designed for securely transferring files between a client and a server on a computer network?",opts:["SMTP","HTTP","FTP","ICMP"],ans:2,exp:"FTP (File Transfer Protocol) is a standard communication protocol used for the transfer of computer files from a server to a client on a computer network. It operates at the Application layer and typically uses TCP ports 20 (data) and 21 (command control)."},hi:{q:"कंप्यूटर नेटवर्क पर क्लाइंट और सर्वर के बीच फाइलों को सुरक्षित रूप से स्थानांतरित करने के लिए कौन सा प्रोटोकॉल मुख्य रूप से डिज़ाइन किया गया है?",opts:["SMTP","HTTP","FTP","ICMP"],ans:2,exp:"FTP (फाइल ट्रांसफर प्रोटोकॉल) एक मानक संचार प्रोटोकॉल है जिसका उपयोग कंप्यूटर नेटवर्क पर सर्वर से क्लाइंट तक कंप्यूटर फ़ाइलों के हस्तांतरण के लिए किया जाता है। यह एप्लिकेशन लेयर पर काम करता है और आमतौर पर TCP पोर्ट 20 और 21 का उपयोग करता है।"}},
{type:"mcq",diff:"easy",en:{q:"What does URL stand for in internet terminology?",opts:["Universal Resource Locator","Uniform Resource Locator","Unified Routing Link","Uniform Registered Link"],ans:1,exp:"URL stands for Uniform Resource Locator. It is the colloquial term for a web address. It specifies the location of a specific resource (like a web page or file) on a computer network and explicitly defines the protocol (e.g., HTTP, FTP) used to retrieve it."},hi:{q:"इंटरनेट शब्दावली में URL का क्या अर्थ है?",opts:["यूनिवर्सल रिसोर्स लोकेटर","यूनिफ़ॉर्म रिसोर्स लोकेटर (Uniform Resource Locator)","यूनिफाइड राउटिंग लिंक","यूनिफॉर्म रजिस्टर्ड लिंक"],ans:1,exp:"URL का अर्थ यूनिफॉर्म रिसोर्स लोकेटर है। यह वेब पते के लिए एक शब्द है। यह कंप्यूटर नेटवर्क पर किसी विशिष्ट संसाधन (जैसे वेब पेज या फ़ाइल) का स्थान निर्दिष्ट करता है और इसे प्राप्त करने के लिए उपयोग किए जाने वाले प्रोटोकॉल (जैसे, HTTP, FTP) को स्पष्ट रूप से परिभाषित करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which protocol is strictly responsible for sending outgoing emails across the internet?",opts:["POP3","IMAP","SMTP","DHCP"],ans:2,exp:"SMTP (Simple Mail Transfer Protocol) is the industry-standard Application layer protocol used explicitly for sending and routing outgoing email messages from a client to a mail server, and between mail servers. It generally operates on TCP port 25, 465, or 587."},hi:{q:"इंटरनेट पर आउटगोइंग ईमेल भेजने के लिए कौन सा प्रोटोकॉल जिम्मेदार है?",opts:["POP3","IMAP","SMTP","DHCP"],ans:2,exp:"SMTP (सिंपल मेल ट्रांसफर प्रोटोकॉल) उद्योग-मानक एप्लिकेशन लेयर प्रोटोकॉल है जिसका उपयोग क्लाइंट से मेल सर्वर तक और मेल सर्वर के बीच आउटगोइंग ईमेल संदेश भेजने और रूट करने के लिए किया जाता है। यह आम तौर पर TCP पोर्ट 25, 465, या 587 पर काम करता है।"}},
{type:"mcq",diff:"easy",en:{q:"What type of connector is typically used to terminate a standard Unshielded Twisted Pair (UTP) Ethernet cable?",opts:["RJ-11","RJ-45","BNC","USB"],ans:1,exp:"RJ-45 (Registered Jack 45) is the standardized 8-pin physical connector used universally to terminate UTP and STP cables for Ethernet networking. It snaps securely into computer NICs, switches, and routers, maintaining the twisted wire integrity up to the connection point."},hi:{q:"एक मानक UTP (Unshielded Twisted Pair) ईथरनेट केबल को समाप्त करने के लिए आमतौर पर किस प्रकार के कनेक्टर का उपयोग किया जाता है?",opts:["RJ-11","RJ-45","BNC","USB"],ans:1,exp:"RJ-45 (रजिस्टर्ड जैक 45) मानकीकृत 8-पिन भौतिक कनेक्टर है जिसका उपयोग ईथरनेट नेटवर्किंग के लिए UTP और STP केबलों को समाप्त करने के लिए सार्वभौमिक रूप से किया जाता है। यह कंप्यूटर NIC, स्विच और राउटर में सुरक्षित रूप से स्नैप करता है।"}},
{type:"mcq",diff:"easy",en:{q:"In networking, what does Wi-Fi stand for?",opts:["Wireless Fidelity","Wired Fiber","Wireless Field","Wide Fidelity"],ans:0,exp:"Wi-Fi is a trademarked phrase that commonly stands for Wireless Fidelity. It represents a family of wireless network protocols, based on the IEEE 802.11 family of standards, which are commonly used for local area networking of devices and Internet access."},hi:{q:"नेटवर्किंग में, Wi-Fi का पूर्ण रूप क्या है?",opts:["वायरलेस फिडेलिटी (Wireless Fidelity)","वायर्ड फाइबर","वायरलेस फील्ड","वाइड फिडेलिटी"],ans:0,exp:"Wi-Fi एक ट्रेडमार्क वाक्यांश है जो आमतौर पर वायरलेस फिडेलिटी के लिए खड़ा है। यह IEEE 802.11 मानकों पर आधारित वायरलेस नेटवर्क प्रोटोकॉल के एक परिवार का प्रतिनिधित्व करता है, जिनका उपयोग स्थानीय क्षेत्र नेटवर्किंग और इंटरनेट एक्सेस के लिए किया जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the full form of the OSI Model in computer networking?",opts:["Open System Interconnection","Open Source Internet","Outer System Interface","Online Secure Interconnection"],ans:0,exp:"OSI stands for Open Systems Interconnection. It is a conceptual reference model created by the ISO (International Organization for Standardization) that standardizes the communication functions of a telecommunication or computing system into seven distinct logical layers."},hi:{q:"कंप्यूटर नेटवर्किंग में OSI मॉडल का पूर्ण रूप क्या है?",opts:["ओपन सिस्टम इंटरकनेक्शन (Open System Interconnection)","ओपन सोर्स इंटरनेट","आउटर सिस्टम इंटरफ़ेस","ऑनलाइन सिक्योर इंटरकनेक्शन"],ans:0,exp:"OSI का अर्थ ओपन सिस्टम इंटरकनेक्शन है। यह ISO द्वारा बनाया गया एक वैचारिक संदर्भ मॉडल है जो दूरसंचार या कंप्यूटिंग प्रणाली के संचार कार्यों को सात अलग-अलग तार्किक परतों में मानकीकृत करता है।"}},
{type:"mcq",diff:"easy",en:{q:"How many distinct layers are there in the standard OSI Reference Model?",opts:["4","5","7","9"],ans:2,exp:"The OSI reference model rigidly defines 7 distinct functional layers to handle network communication: Physical (1), Data Link (2), Network (3), Transport (4), Session (5), Presentation (6), and Application (7). Each layer serves the layer directly above it."},hi:{q:"मानक OSI संदर्भ मॉडल में कितनी अलग-अलग परतें (layers) होती हैं?",opts:["4","5","7","9"],ans:2,exp:"OSI संदर्भ मॉडल नेटवर्क संचार को संभालने के लिए 7 अलग-अलग कार्यात्मक परतों को परिभाषित करता है: फिजिकल (1), डेटा लिंक (2), नेटवर्क (3), ट्रांसपोर्ट (4), सेशन (5), प्रेजेंटेशन (6), और एप्लीकेशन (7)।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following best defines an 'Intranet'?",opts:["A public network accessible globally","A private, secure network restricted to users within a specific organization","A network used by hackers to hide identity","A network consisting only of routers"],ans:1,exp:"An Intranet is a highly secure, private enterprise network based on internet protocols (TCP/IP). It is strictly restricted to authorized employees or members within an organization to share company information, operational systems, and computing resources safely."},hi:{q:"निम्नलिखित में से कौन 'Intranet' (इंट्रानेट) को सबसे अच्छी तरह परिभाषित करता है?",opts:["वैश्विक स्तर पर सुलभ एक सार्वजनिक नेटवर्क","एक विशिष्ट संगठन के भीतर उपयोगकर्ताओं तक सीमित एक निजी, सुरक्षित नेटवर्क","हैकर्स द्वारा पहचान छिपाने के लिए उपयोग किया जाने वाला नेटवर्क","केवल राउटर से युक्त एक नेटवर्क"],ans:1,exp:"इंट्रानेट इंटरनेट प्रोटोकॉल (TCP/IP) पर आधारित एक अत्यधिक सुरक्षित, निजी उद्यम नेटवर्क है। यह कंपनी की जानकारी, परिचालन प्रणाली और कंप्यूटिंग संसाधनों को सुरक्षित रूप से साझा करने के लिए किसी संगठन के भीतर अधिकृत कर्मचारियों या सदस्यों तक सख्ती से सीमित है।"}},
{type:"mcq",diff:"easy",en:{q:"What does MAN stand for in network types?",opts:["Metropolitan Area Network","Mobile Area Network","Maximum Access Network","Multiple Area Node"],ans:0,exp:"MAN stands for Metropolitan Area Network. It is a computer network that interconnects users with computer resources in a geographic area or region larger than that covered by even a large local area network (LAN) but smaller than the area covered by a wide area network (WAN), like an entire city."},hi:{q:"नेटवर्क प्रकारों में MAN का क्या अर्थ है?",opts:["मेट्रोपॉलिटन एरिया नेटवर्क (Metropolitan Area Network)","मोबाइल एरिया नेटवर्क","मैक्सिमम एक्सेस नेटवर्क","मल्टीपल एरिया नोड"],ans:0,exp:"MAN का अर्थ मेट्रोपॉलिटन एरिया नेटवर्क है। यह एक कंप्यूटर नेटवर्क है जो उपयोगकर्ताओं को एक बड़े शहर या भौगोलिक क्षेत्र में कंप्यूटर संसाधनों से जोड़ता है, जो LAN से बड़ा लेकिन WAN (वाइड एरिया नेटवर्क) से छोटा होता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which network topology is a hybrid combination of Star and Bus topologies?",opts:["Ring Topology","Tree Topology","Mesh Topology","Hybrid Topology"],ans:1,exp:"The Tree Topology (or hierarchical topology) integrates multiple Star topologies onto a single central Bus backbone cable. This provides excellent scalability, allowing individual star-configured sub-networks to be added or removed without disrupting the central bus architecture."},hi:{q:"कौन सी नेटवर्क टोपोलॉजी स्टार (Star) और बस (Bus) टोपोलॉजी का एक हाइब्रिड संयोजन है?",opts:["रिंग टोपोलॉजी","ट्री टोपोलॉजी (Tree Topology)","मेश टोपोलॉजी","हाइब्रिड टोपोलॉजी"],ans:1,exp:"ट्री टोपोलॉजी (या पदानुक्रमित टोपोलॉजी) एक एकल केंद्रीय बस बैकबोन केबल पर कई स्टार टोपोलॉजी को एकीकृत करती है। यह उत्कृष्ट स्केलेबिलिटी प्रदान करता है, जिससे केंद्रीय बस वास्तुकला को बाधित किए बिना व्यक्तिगत उप-नेटवर्क को जोड़ने या हटाने की अनुमति मिलती है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the primary function of a Network Interface Card (NIC)?",opts:["To print documents","To physically connect a computer to a local network","To protect the computer from viruses","To process graphics and images"],ans:1,exp:"A Network Interface Card (NIC) is a hardware component (often integrated into the motherboard) that provides a physical connection to a computer network. It converts serial data into parallel data for the CPU and possesses a unique MAC address for network identification."},hi:{q:"नेटवर्क इंटरफ़ेस कार्ड (NIC) का प्राथमिक कार्य क्या है?",opts:["दस्तावेज प्रिंट करने के लिए","कंप्यूटर को भौतिक रूप से स्थानीय नेटवर्क (local network) से जोड़ने के लिए","कंप्यूटर को वायरस से बचाने के लिए","ग्राफिक्स और छवियों को प्रोसेस करने के लिए"],ans:1,exp:"नेटवर्क इंटरफेस कार्ड (NIC) एक हार्डवेयर घटक है जो कंप्यूटर नेटवर्क को भौतिक कनेक्शन प्रदान करता है। यह CPU के लिए सीरियल डेटा को समानांतर डेटा में परिवर्तित करता है और इसमें नेटवर्क पहचान के लिए एक अद्वितीय MAC पता होता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the fixed length of an IPv4 address?",opts:["16 bits","32 bits","64 bits","128 bits"],ans:1,exp:"An IPv4 (Internet Protocol version 4) address is structurally a 32-bit binary number. It is conventionally formatted into four 8-bit octets separated by dots (e.g., 192.168.1.1), providing approximately 4.3 billion unique mathematical addresses globally."},hi:{q:"IPv4 एड्रेस की निश्चित लंबाई क्या होती है?",opts:["16 bits","32 bits","64 bits","128 bits"],ans:1,exp:"एक IPv4 (इंटरनेट प्रोटोकॉल संस्करण 4) पता संरचनात्मक रूप से 32-बिट बाइनरी नंबर है। इसे पारंपरिक रूप से बिंदुओं (जैसे, 192.168.1.1) द्वारा अलग किए गए चार 8-बिट ऑक्टेट में स्वरूपित किया जाता है, जो विश्व स्तर पर लगभग 4.3 बिलियन अद्वितीय पते प्रदान करता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the basic purpose of DNS (Domain Name System)?",opts:["To route packets across routers","To translate human-readable domain names into numerical IP addresses","To secure email transmission","To assign MAC addresses to NICs"],ans:1,exp:"DNS acts as the phonebook of the internet. Because networking equipment strictly routes traffic using numerical IP addresses, DNS seamlessly translates human-friendly domain names (like www.google.com) into their underlying machine-readable IP addresses (like 142.250.190.46)."},hi:{q:"DNS (Domain Name System) का मूल उद्देश्य क्या है?",opts:["पैकेट को राउटर के पार रूट करना","मानव-पठनीय डोमेन नामों (domain names) को संख्यात्मक IP पतों (IP addresses) में अनुवाद करना","ईमेल ट्रांसमिशन को सुरक्षित करना","NIC को MAC पता निर्दिष्ट करना"],ans:1,exp:"DNS इंटरनेट की फोनबुक के रूप में कार्य करता है। चूंकि नेटवर्किंग उपकरण संख्यात्मक IP पतों का उपयोग करके ट्रैफ़िक को रूट करते हैं, DNS मानव-अनुकूल डोमेन नामों (जैसे www.google.com) को उनके अंतर्निहित मशीन-पठनीय IP पतों में अनुवाद करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which organization regulates and standardizes global web technologies, including HTML and CSS?",opts:["IEEE","IETF","W3C (World Wide Web Consortium)","IANA"],ans:2,exp:"The World Wide Web Consortium (W3C), founded by Tim Berners-Lee, is the main international standards organization for the World Wide Web. It develops technical specifications and guidelines (like HTML, CSS, XML) to ensure long-term, standardized web growth and accessibility."},hi:{q:"HTML और CSS सहित वैश्विक वेब तकनीकों को कौन सा संगठन नियंत्रित और मानकीकृत करता है?",opts:["IEEE","IETF","W3C (World Wide Web Consortium)","IANA"],ans:2,exp:"टिम बर्नर्स-ली द्वारा स्थापित वर्ल्ड वाइड वेब कंसोर्टियम (W3C), वर्ल्ड वाइड वेब के लिए मुख्य अंतरराष्ट्रीय मानक संगठन है। यह दीर्घकालिक, मानकीकृत वेब विकास और पहुंच सुनिश्चित करने के लिए तकनीकी विनिर्देश और दिशानिर्देश विकसित करता है।"}},
{type:"mcq",diff:"easy",en:{q:"What does HTTP stand for?",opts:["HyperText Transfer Protocol","Hyperlink Transfer Technology","Host Transmission Type Protocol","HyperText Transmission Procedure"],ans:0,exp:"HTTP stands for HyperText Transfer Protocol. It operates at the Application Layer and is the fundamental protocol used to fetch HTML documents, images, and data across the World Wide Web, forming the foundation of client-server web data communication."},hi:{q:"HTTP का पूर्ण रूप क्या है?",opts:["हाइपरटेक्स्ट ट्रांसफर प्रोटोकॉल (HyperText Transfer Protocol)","हाइपरलिंक ट्रांसफर टेक्नोलॉजी","होस्ट ट्रांसमिशन टाइप प्रोटोकॉल","हाइपरटेक्स्ट ट्रांसमिशन प्रोसीजर"],ans:0,exp:"HTTP का अर्थ हाइपरटेक्स्ट ट्रांसफर प्रोटोकॉल है। यह एप्लिकेशन लेयर पर काम करता है और वर्ल्ड वाइड वेब पर HTML दस्तावेज़ों, छवियों और डेटा को प्राप्त करने के लिए उपयोग किया जाने वाला मौलिक प्रोटोकॉल है, जो वेब डेटा संचार की नींव बनाता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following describes a 'Client' in client-server architecture?",opts:["A powerful machine that stores all centralized data","A device or software that requests services and resources from a server","A physical switch connecting multiple computers","A database management system"],ans:1,exp:"In the client-server networking model, a 'Client' is the end-user device (like a laptop or smartphone) or software application (like a web browser) that actively initiates requests for data, files, or processing resources from a centralized, powerful 'Server'."},hi:{q:"क्लाइंट-सर्वर आर्किटेक्चर में 'क्लाइंट' (Client) का वर्णन निम्नलिखित में से कौन करता है?",opts:["एक शक्तिशाली मशीन जो सभी केंद्रीकृत डेटा संग्रहीत करती है","एक उपकरण या सॉफ्टवेयर जो सर्वर से सेवाओं और संसाधनों का अनुरोध करता है","कई कंप्यूटरों को जोड़ने वाला एक भौतिक स्विच","एक डेटाबेस मैनेजमेंट सिस्टम"],ans:1,exp:"क्लाइंट-सर्वर नेटवर्किंग मॉडल में, एक 'क्लाइंट' अंतिम-उपयोगकर्ता उपकरण (जैसे लैपटॉप) या सॉफ़्टवेयर एप्लिकेशन (जैसे वेब ब्राउज़र) है जो सक्रिय रूप से एक केंद्रीकृत, शक्तिशाली 'सर्वर' से डेटा, फ़ाइलों या संसाधनों के लिए अनुरोध शुरू करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which type of network is specifically used to connect devices within a person's immediate workspace, typically using Bluetooth?",opts:["WAN","PAN","MAN","WLAN"],ans:1,exp:"A PAN (Personal Area Network) covers a very short range, usually within 10 meters of an individual. It is utilized to interconnect personal devices like smartphones, wireless headsets, smartwatches, and laptops, predominantly utilizing Bluetooth or near-field communication technologies."},hi:{q:"किसी व्यक्ति के तत्काल कार्यक्षेत्र में उपकरणों को जोड़ने के लिए विशेष रूप से किस प्रकार के नेटवर्क का उपयोग किया जाता है, आमतौर पर ब्लूटूथ का उपयोग करके?",opts:["WAN","PAN (Personal Area Network)","MAN","WLAN"],ans:1,exp:"एक PAN (पर्सनल एरिया नेटवर्क) एक बहुत छोटी दूरी को कवर करता है, आमतौर पर एक व्यक्ति के 10 मीटर के भीतर। इसका उपयोग व्यक्तिगत उपकरणों जैसे स्मार्टफोन, वायरलेस हेडसेट और लैपटॉप को आपस में जोड़ने के लिए किया जाता है, मुख्य रूप से ब्लूटूथ का उपयोग करके।"}},
{type:"mcq",diff:"easy",en:{q:"What is the primary function of an ISP (Internet Service Provider)?",opts:["To manufacture networking hardware","To provide individuals and businesses access to the internet","To design web pages","To secure computer files with encryption"],ans:1,exp:"An ISP (Internet Service Provider) is a commercial organization (like Airtel, Jio, AT&T) that provides the physical infrastructure and gateway access enabling consumers and businesses to connect to the global Internet, usually via broadband, fiber, or cellular networks."},hi:{q:"ISP (Internet Service Provider) का प्राथमिक कार्य क्या है?",opts:["नेटवर्किंग हार्डवेयर का निर्माण करना","व्यक्तियों और व्यवसायों को इंटरनेट तक पहुंच प्रदान करना","वेब पेज डिजाइन करने के लिए","एन्क्रिप्शन के साथ कंप्यूटर फाइलों को सुरक्षित करने के लिए"],ans:1,exp:"एक ISP (इंटरनेट सर्विस प्रोवाइडर) एक वाणिज्यिक संगठन है जो भौतिक बुनियादी ढांचे और गेटवे एक्सेस प्रदान करता है जो उपभोक्ताओं और व्यवसायों को वैश्विक इंटरनेट से जुड़ने में सक्षम बनाता है, आमतौर पर ब्रॉडबैंड, फाइबर या सेलुलर नेटवर्क के माध्यम से।"}},

// EASY: 2 True/False
{type:"tf",diff:"easy",en:{q:"In a Simplex transmission mode, data can travel in both directions simultaneously like a telephone call.",opts:["True","False"],ans:1,exp:"False. In Simplex mode, data communication is strictly unidirectional (one-way only), like a television or radio broadcast. Full-Duplex is the mode that allows simultaneous bidirectional communication like a telephone call."},hi:{q:"सिंप्लेक्स (Simplex) ट्रांसमिशन मोड में, डेटा एक टेलीफोन कॉल की तरह एक साथ दोनों दिशाओं में यात्रा कर सकता है।",opts:["सही","गलत"],ans:1,exp:"गलत। सिंप्लेक्स मोड में, डेटा संचार कड़ाई से एक दिशा में होता है (केवल एक तरफा), जैसे टेलीविजन या रेडियो प्रसारण। फुल-डुप्लेक्स वह मोड है जो टेलीफोन कॉल की तरह एक साथ द्विदिश संचार की अनुमति देता है।"}},
{type:"tf",diff:"easy",en:{q:"A Web Browser is an application software used to access and view websites on the Internet.",opts:["True","False"],ans:0,exp:"True. A Web Browser (like Chrome, Firefox, or Edge) is a dedicated client-side software application that interprets HTML code, executes scripts, and graphically renders content retrieved from web servers so users can easily view and navigate websites."},hi:{q:"वेब ब्राउज़र (Web Browser) एक एप्लीकेशन सॉफ्टवेयर है जिसका उपयोग इंटरनेट पर वेबसाइटों तक पहुंचने और देखने के लिए किया जाता है।",opts:["सही","गलत"],ans:0,exp:"सही। वेब ब्राउज़र (जैसे क्रोम, फ़ायरफ़ॉक्स) एक समर्पित क्लाइंट-साइड सॉफ़्टवेयर है जो HTML कोड की व्याख्या करता है, स्क्रिप्ट निष्पादित करता है, और वेब सर्वर से प्राप्त सामग्री को ग्राफिक रूप से प्रस्तुत करता है ताकि उपयोगकर्ता वेबसाइटों को आसानी से देख सकें।"}},

// ==========================================
// MEDIUM: 28 MCQs
// ==========================================
{type:"mcq",diff:"medium",en:{q:"What is the key difference between a Switch and a Hub?",opts:["A Hub operates at Layer 3; a Switch operates at Layer 1","A Switch intelligently forwards data to a specific device using MAC addresses, while a Hub blindly broadcasts data to all ports","A Switch is strictly for wireless networks, Hub is for wired networks","A Hub is faster than a Switch"],ans:1,exp:"A Switch (Layer 2 device) builds a MAC address table to intelligently unicast frames exactly to the intended recipient port, maximizing bandwidth. A Hub (Layer 1 device) lacks memory; it simply duplicates incoming electrical signals out to every single port, creating severe network congestion."},hi:{q:"स्विच (Switch) और हब (Hub) के बीच मुख्य अंतर क्या है?",opts:["एक हब लेयर 3 पर काम करता है; एक स्विच लेयर 1 पर काम करता है","एक स्विच MAC एड्रेस का उपयोग करके डेटा को एक विशिष्ट डिवाइस पर बुद्धिमानी से अग्रेषित करता है, जबकि एक हब सभी पोर्ट पर डेटा प्रसारित (broadcast) करता है","एक स्विच कड़ाई से वायरलेस नेटवर्क के लिए है, हब वायर्ड नेटवर्क के लिए है","एक हब स्विच से तेज होता है"],ans:1,exp:"एक स्विच (लेयर 2 डिवाइस) बैंडविड्थ को अधिकतम करने के लिए मैक एड्रेस टेबल बनाता है। एक हब (लेयर 1 डिवाइस) में मेमोरी का अभाव होता है; यह बस हर एक पोर्ट पर आने वाले विद्युत संकेतों की नकल करता है, जिससे गंभीर नेटवर्क भीड़ पैदा होती है।"}},
{type:"mcq",diff:"medium",en:{q:"At which layer of the OSI model does a Router operate?",opts:["Data Link Layer","Transport Layer","Network Layer","Physical Layer"],ans:2,exp:"Routers operate at Layer 3, the Network Layer. Their primary function is to inspect the logical IP addresses of incoming packets and use internal routing tables to determine the most optimal path to forward those packets across multiple distinct networks."},hi:{q:"OSI मॉडल की किस लेयर (Layer) पर एक राउटर (Router) काम करता है?",opts:["डेटा लिंक लेयर","ट्रांसपोर्ट लेयर","नेटवर्क लेयर (Network Layer)","फिजिकल लेयर"],ans:2,exp:"राउटर लेयर 3, नेटवर्क लेयर पर काम करते हैं। उनका प्राथमिक कार्य आने वाले पैकेटों के तार्किक आईपी पते (IP addresses) का निरीक्षण करना और कई अलग-अलग नेटवर्क पर उन पैकेटों को अग्रेषित करने के लिए सबसे इष्टतम मार्ग निर्धारित करने के लिए आंतरिक राउटिंग तालिकाओं का उपयोग करना है।"}},
{type:"mcq",diff:"medium",en:{q:"Which OSI layer is responsible for end-to-end error recovery, reliability, and flow control?",opts:["Session Layer","Transport Layer","Network Layer","Application Layer"],ans:1,exp:"The Transport Layer (Layer 4) is accountable for reliable end-to-end message delivery. It uses protocols like TCP to implement segmentation, connection multiplexing, flow control (windowing), and strict error recovery through acknowledgment and retransmission mechanisms."},hi:{q:"एंड-टू-एंड त्रुटि पुनर्प्राप्ति (error recovery), विश्वसनीयता और प्रवाह नियंत्रण (flow control) के लिए कौन सी OSI लेयर जिम्मेदार है?",opts:["सेशन लेयर","ट्रांसपोर्ट लेयर (Transport Layer)","नेटवर्क लेयर","एप्लिकेशन लेयर"],ans:1,exp:"ट्रांसपोर्ट लेयर (लेयर 4) विश्वसनीय एंड-टू-एंड संदेश वितरण के लिए जवाबदेह है। यह विभाजन, प्रवाह नियंत्रण (विंडोइंग), और पावती और पुन: संचरण तंत्र के माध्यम से सख्त त्रुटि वसूली को लागू करने के लिए TCP जैसे प्रोटोकॉल का उपयोग करता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which of the following is the standard, well-known port number for HTTP traffic?",opts:["21","25","80","443"],ans:2,exp:"Port 80 is the universally assigned, standard well-known port for unencrypted HTTP (HyperText Transfer Protocol) web traffic. Web servers listen on this specific TCP port to accept incoming connections from web browsers requesting standard web pages."},hi:{q:"निम्नलिखित में से कौन सा HTTP ट्रैफ़िक के लिए मानक, प्रसिद्ध पोर्ट नंबर (port number) है?",opts:["21","25","80","443"],ans:2,exp:"पोर्ट 80 अनएन्क्रिप्टेड HTTP वेब ट्रैफ़िक के लिए सार्वभौमिक रूप से निर्दिष्ट, मानक पोर्ट है। वेब सर्वर मानक वेब पृष्ठों का अनुरोध करने वाले वेब ब्राउज़र से आने वाले कनेक्शन को स्वीकार करने के लिए इस विशिष्ट TCP पोर्ट को सुनते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"To ensure secure, encrypted communication over the web (HTTPS), which port does a web server actively listen on by default?",opts:["80","8080","443","22"],ans:2,exp:"HTTPS (HTTP Secure) uses TLS/SSL encryption to secure data packets during transit between the browser and server. By strict standard convention, HTTPS traffic is routed through TCP port 443, segregating it from the unencrypted port 80 traffic."},hi:{q:"वेब (HTTPS) पर सुरक्षित, एन्क्रिप्टेड संचार सुनिश्चित करने के लिए, वेब सर्वर डिफ़ॉल्ट रूप से किस पोर्ट पर सक्रिय रूप से सुनता है?",opts:["80","8080","443","22"],ans:2,exp:"HTTPS (HTTP सिक्योर) ब्राउज़र और सर्वर के बीच पारगमन के दौरान डेटा पैकेट को सुरक्षित करने के लिए TLS/SSL एन्क्रिप्शन का उपयोग करता है। सख्त मानक सम्मेलन द्वारा, HTTPS ट्रैफ़िक को TCP पोर्ट 443 के माध्यम से रूट किया जाता है, इसे अनएन्क्रिप्टेड पोर्ट 80 ट्रैफ़िक से अलग किया जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which OSI layer manages data formatting, compression, and encryption to ensure the data is readable by the receiving system?",opts:["Application Layer","Presentation Layer","Session Layer","Data Link Layer"],ans:1,exp:"The Presentation Layer (Layer 6) acts as the network's data translator. It handles syntax processing, data compression (like JPEG formatting), and deep encryption/decryption (like SSL/TLS) so the Application layer receives data in a standardized, readable format."},hi:{q:"कौन सी OSI लेयर डेटा फॉर्मेटिंग, कम्प्रेशन और एन्क्रिप्शन का प्रबंधन करती है ताकि यह सुनिश्चित हो सके कि डेटा प्राप्त करने वाले सिस्टम द्वारा पढ़ने योग्य है?",opts:["एप्लिकेशन लेयर","प्रेजेंटेशन लेयर (Presentation Layer)","सेशन लेयर","डेटा लिंक लेयर"],ans:1,exp:"प्रेजेंटेशन लेयर (लेयर 6) नेटवर्क के डेटा अनुवादक के रूप में कार्य करती है। यह सिंटैक्स प्रोसेसिंग, डेटा कम्प्रेशन (जैसे JPEG फॉर्मेटिंग), और डीप एन्क्रिप्शन/डिक्रिप्शन को संभालती है ताकि एप्लीकेशन लेयर को मानकीकृत, पठनीय प्रारूप में डेटा प्राप्त हो।"}},
{type:"mcq",diff:"medium",en:{q:"In IPv4 classful addressing, what is the valid range of the first octet for a Class B address?",opts:["1 - 126","128 - 191","192 - 223","224 - 239"],ans:1,exp:"Under standard classful IPv4 addressing architecture, a Class B network address begins with a binary 10. Mathematically, this dictates that the very first octet in decimal format must strictly fall within the range of 128 through 191 inclusive. Class B supports 65,534 hosts per network."},hi:{q:"IPv4 क्लासफुल एड्रेसिंग में, क्लास B एड्रेस के लिए पहले ऑक्टेट (octet) की मान्य सीमा क्या है?",opts:["1 - 126","128 - 191","192 - 223","224 - 239"],ans:1,exp:"मानक क्लासफुल IPv4 एड्रेसिंग आर्किटेक्चर के तहत, एक क्लास B नेटवर्क एड्रेस बाइनरी 10 से शुरू होता है। गणितीय रूप से, यह निर्देश देता है कि दशमलव प्रारूप में पहला ऑक्टेट 128 से 191 की सीमा के भीतर आना चाहिए। क्लास बी प्रति नेटवर्क 65,534 होस्ट का समर्थन करता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which IP address is specifically reserved worldwide for Local Loopback testing to check if the internal TCP/IP stack is functioning?",opts:["0.0.0.0","255.255.255.255","127.0.0.1","169.254.0.1"],ans:2,exp:"The IP address 127.0.0.1 (and the entire 127.0.0.0/8 block) is strictly reserved as the host loopback address. Pinging this address does not send packets out to the network hardware; instead, it bounces the signal back internally to verify the OS's software TCP/IP protocol stack is working."},hi:{q:"आंतरिक TCP/IP स्टैक काम कर रहा है या नहीं, यह जांचने के लिए लोकल लूपबैक (Local Loopback) परीक्षण के लिए विशेष रूप से कौन सा IP पता आरक्षित है?",opts:["0.0.0.0","255.255.255.255","127.0.0.1","169.254.0.1"],ans:2,exp:"IP पता 127.0.0.1 को होस्ट लूपबैक पते के रूप में आरक्षित किया गया है। इस पते को पिंग करने से नेटवर्क हार्डवेयर पर पैकेट नहीं जाते हैं; इसके बजाय, यह यह सत्यापित करने के लिए कि ओएस का सॉफ्टवेयर टीसीपी/आईपी प्रोटोकॉल स्टैक काम कर रहा है, सिग्नल को आंतरिक रूप से वापस उछालता है।"}},
{type:"mcq",diff:"medium",en:{q:"How is a standard 48-bit MAC address typically represented visually in software?",opts:["Four decimal numbers separated by dots (e.g., 192.168.1.1)","Six groups of two hexadecimal digits (e.g., 00:1A:2B:3C:4D:5E)","A single long binary string","A domain name URL"],ans:1,exp:"A MAC address consists of 48 bits, but displaying 48 ones and zeros is unreadable for humans. Therefore, it is universally represented in hexadecimal format, visually broken down into six groups (octets) of two hex digits, separated by colons or hyphens (e.g., 0A:1B:2C:3D:4E:5F)."},hi:{q:"एक मानक 48-बिट MAC एड्रेस को आमतौर पर सॉफ्टवेयर में कैसे प्रदर्शित किया जाता है?",opts:["बिंदुओं द्वारा अलग की गई चार दशमलव संख्याएँ (जैसे, 192.168.1.1)","दो हेक्साडेसिमल अंकों के छह समूह (उदा., 00:1A:2B:3C:4D:5E)","एक एकल लंबी बाइनरी स्ट्रिंग","एक डोमेन नाम URL"],ans:1,exp:"एक MAC पते में 48 बिट होते हैं, लेकिन 48 वाले और शून्य प्रदर्शित करना मनुष्यों के लिए अपठनीय है। इसलिए, इसे सार्वभौमिक रूप से हेक्साडेसिमल प्रारूप में दर्शाया जाता है, जिसे नेत्रहीन रूप से दो हेक्स अंकों के छह समूहों (ऑक्टेट्स) में विभाजित किया जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"What is the primary physical transmission principle that allows Fiber Optic cables to guide light over long distances without data loss?",opts:["Electromagnetic Induction","Total Internal Reflection","Radio Frequency Modulation","Capacitance Coupling"],ans:1,exp:"Fiber optic cables utilize the optical phenomenon of 'Total Internal Reflection'. The cable contains a glass core surrounded by a cladding layer with a slightly lower refractive index. When a laser or LED injects light pulses, they continuously bounce off the cladding boundaries, trapping the light perfectly inside the core."},hi:{q:"वह प्राथमिक भौतिक संचरण सिद्धांत (transmission principle) क्या है जो फाइबर ऑप्टिक (Fiber Optic) केबलों को बिना डेटा हानि के लंबी दूरी तक प्रकाश का मार्गदर्शन करने की अनुमति देता है?",opts:["विद्युत चुम्बकीय प्रेरण (Electromagnetic Induction)","कुल आंतरिक परावर्तन (Total Internal Reflection)","रेडियो आवृत्ति मॉडुलन (Radio Frequency Modulation)","कैपेसिटेंस कपलिंग (Capacitance Coupling)"],ans:1,exp:"फाइबर ऑप्टिक केबल 'कुल आंतरिक परावर्तन' (Total Internal Reflection) की ऑप्टिकल घटना का उपयोग करते हैं। केबल में कांच का कोर होता है जो थोड़ी कम अपवर्तक सूचकांक के साथ क्लैडिंग परत से घिरा होता है। प्रकाश लगातार क्लैडिंग सीमाओं से उछलता है, जिससे प्रकाश कोर के अंदर पूरी तरह से फंस जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"In network architecture, what is the specific role of a 'Gateway' device?",opts:["To connect multiple computers in a small room","To connect two networks that use entirely different architectures and protocols (e.g., a LAN to the Internet)","To amplify a weak signal on a long cable","To block all external internet traffic"],ans:1,exp:"A Gateway is a highly complex node (often a router or specialized server) that serves as an entrance to another network. Unlike a bridge which connects similar networks, a gateway acts as a protocol converter, translating data formats so two entirely different networks (like a private IP LAN and the global Internet) can communicate."},hi:{q:"नेटवर्क आर्किटेक्चर में, 'गेटवे' (Gateway) डिवाइस की विशिष्ट भूमिका क्या है?",opts:["एक छोटे से कमरे में कई कंप्यूटरों को जोड़ने के लिए","पूरी तरह से अलग आर्किटेक्चर और प्रोटोकॉल का उपयोग करने वाले दो नेटवर्क कनेक्ट करने के लिए (जैसे, इंटरनेट से एक LAN)","एक लंबी केबल पर कमजोर सिग्नल को बढ़ाने के लिए","सभी बाहरी इंटरनेट ट्रैफ़िक को अवरुद्ध करने के लिए"],ans:1,exp:"एक गेटवे एक अत्यधिक जटिल नोड (अक्सर एक राउटर या विशेष सर्वर) है जो दूसरे नेटवर्क के प्रवेश द्वार के रूप में कार्य करता है। एक ब्रिज के विपरीत जो समान नेटवर्क को जोड़ता है, एक गेटवे एक प्रोटोकॉल कनवर्टर के रूप में कार्य करता है, डेटा प्रारूपों का अनुवाद करता है ताकि दो पूरी तरह से अलग नेटवर्क संवाद कर सकें।"}},
{type:"mcq",diff:"medium",en:{q:"Which of the following describes a key characteristic of the UDP (User Datagram Protocol)?",opts:["It guarantees data delivery using acknowledgments","It is connectionless and does not verify if packets reach their destination","It physically establishes a 3-way handshake before sending data","It automatically retransmits lost packets"],ans:1,exp:"UDP operates at the Transport layer as a 'Connectionless' protocol. It simply wraps data in datagrams and blasts them out to the destination without establishing a prior connection. It does not use acknowledgments, meaning it does not guarantee delivery, making it incredibly fast but unreliable (used for live video/VoIP)."},hi:{q:"निम्नलिखित में से कौन सा UDP (यूज़र डेटाग्राम प्रोटोकॉल) की प्रमुख विशेषता का वर्णन करता है?",opts:["यह पावती (acknowledgments) का उपयोग करके डेटा वितरण की गारंटी देता है","यह कनेक्शन रहित (connectionless) है और यह सत्यापित नहीं करता है कि पैकेट अपने गंतव्य तक पहुंचते हैं या नहीं","यह डेटा भेजने से पहले भौतिक रूप से 3-वे हैंडशेक स्थापित करता है","यह खोए हुए पैकेटों को स्वचालित रूप से पुनः प्रेषित करता है"],ans:1,exp:"UDP ट्रांसपोर्ट लेयर पर 'कनेक्शनलेस' प्रोटोकॉल के रूप में काम करता है। यह केवल डेटा को डेटाग्राम में लपेटता है और पूर्व कनेक्शन स्थापित किए बिना गंतव्य तक भेजता है। यह वितरण की गारंटी नहीं देता है, जिससे यह अविश्वसनीय रूप से तेज लेकिन अविश्वसनीय (लाइव वीडियो/VoIP के लिए उपयोग किया जाता है) हो जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"What does the DHCP protocol dynamically assign to client computers joining a network?",opts:["A permanent MAC address","A physical hard drive partition","An IP Address, Subnet Mask, and Default Gateway","Antivirus definitions"],ans:2,exp:"DHCP (Dynamic Host Configuration Protocol) operates at the Application layer. It completely automates network configuration. When a new device boots up, DHCP dynamically leases it a unique IP address, the correct Subnet mask, the Router (Default Gateway) IP, and the DNS server IPs, eliminating tedious manual configuration."},hi:{q:"नेटवर्क से जुड़ने वाले क्लाइंट कंप्यूटरों को DHCP प्रोटोकॉल गतिशील रूप से क्या असाइन (assign) करता है?",opts:["एक स्थायी MAC पता","एक भौतिक हार्ड ड्राइव विभाजन","एक IP एड्रेस, सबनेट मास्क और डिफ़ॉल्ट गेटवे","एंटीवायरस परिभाषाएँ"],ans:2,exp:"DHCP (डायनामिक होस्ट कॉन्फ़िगरेशन प्रोटोकॉल) एप्लिकेशन लेयर पर काम करता है। यह नेटवर्क कॉन्फ़िगरेशन को पूरी तरह से स्वचालित करता है। जब एक नया उपकरण बूट होता है, तो DHCP गतिशील रूप से इसे एक अद्वितीय आईपी पता, सही सबनेट मास्क, राउटर (डिफ़ॉल्ट गेटवे) आईपी और डीएनएस सर्वर आईपी पट्टे पर देता है।"}},
{type:"mcq",diff:"medium",en:{q:"When a network administrator uses the 'ping' command in the terminal, which underlying protocol is primarily being utilized?",opts:["TCP","HTTP","ICMP","FTP"],ans:2,exp:"The 'ping' utility relies entirely on ICMP (Internet Control Message Protocol). It functions by sending an 'ICMP Echo Request' packet to a target IP. If the target is alive and reachable, it responds with an 'ICMP Echo Reply'. This diagnostic exchange verifies layer 3 network connectivity and measures round-trip latency."},hi:{q:"जब कोई नेटवर्क प्रशासक टर्मिनल में 'ping' कमांड का उपयोग करता है, तो मुख्य रूप से किस अंतर्निहित प्रोटोकॉल का उपयोग किया जा रहा है?",opts:["TCP","HTTP","ICMP","FTP"],ans:2,exp:"'पिंग' (ping) कमांड पूरी तरह से ICMP (इंटरनेट कंट्रोल मैसेज प्रोटोकॉल) पर निर्भर करता है। यह लक्ष्य IP पर 'ICMP इको रिक्वेस्ट' पैकेट भेजकर काम करता है। यदि लक्ष्य चालू है, तो वह 'ICMP इको रिप्लाई' के साथ प्रतिक्रिया करता है। यह निदान नेटवर्क कनेक्टिविटी की पुष्टि करता है।"}},
{type:"mcq",diff:"medium",en:{q:"What is the default Subnet Mask for a standard Class C IPv4 network address?",opts:["255.0.0.0","255.255.0.0","255.255.255.0","255.255.255.255"],ans:2,exp:"In classful networking architecture, a Class C network reserves the first 24 bits (3 octets) strictly for the Network ID, leaving only the final 8 bits for Host IDs. Therefore, its default mathematically mandated Subnet Mask is 255.255.255.0, allowing a maximum of 254 usable hosts per subnet."},hi:{q:"एक मानक क्लास सी (Class C) IPv4 नेटवर्क पते के लिए डिफ़ॉल्ट सबनेट मास्क क्या है?",opts:["255.0.0.0","255.255.0.0","255.255.255.0","255.255.255.255"],ans:2,exp:"क्लासफुल नेटवर्किंग आर्किटेक्चर में, क्लास सी नेटवर्क पहले 24 बिट्स (3 ऑक्टेट्स) को सख्ती से नेटवर्क आईडी के लिए सुरक्षित रखता है, केवल अंतिम 8 बिट्स को होस्ट आईडी के लिए छोड़ता है। इसलिए, इसका डिफ़ॉल्ट सबनेट मास्क 255.255.255.0 है, जो प्रति सबनेट अधिकतम 254 प्रयोग करने योग्य होस्ट की अनुमति देता है।"}},
{type:"mcq",diff:"medium",en:{q:"What critical diagnostic information does the 'tracert' (or traceroute) command display?",opts:["The MAC address of the destination website","The step-by-step path (list of specific routers) a packet takes to reach a destination IP","The amount of RAM installed on the server","The encryption keys used for HTTPS"],ans:1,exp:"The 'traceroute' diagnostic tool exploits the IP packet 'Time to Live' (TTL) field. It maps out the exact route data packets take across the internet. It lists the IP address and latency of every single intermediate router (hop) crossed between the source computer and the final destination server."},hi:{q:"'tracert' (या traceroute) कमांड कौन सी महत्वपूर्ण नैदानिक ​​जानकारी (diagnostic information) प्रदर्शित करता है?",opts:["गंतव्य वेबसाइट का MAC पता","चरण-दर-चरण मार्ग (विशिष्ट राउटर की सूची) जो एक पैकेट गंतव्य IP तक पहुंचने के लिए लेता है","सर्वर पर स्थापित RAM की मात्रा","HTTPS के लिए उपयोग की जाने वाली एन्क्रिप्शन कुंजियाँ"],ans:1,exp:"'ट्रेसरूट' टूल आईपी पैकेट 'टाइम टू लिव' (TTL) क्षेत्र का फायदा उठाता है। यह इंटरनेट पर डेटा पैकेट लेने वाले सटीक मार्ग का नक्शा तैयार करता है। यह स्रोत कंप्यूटर और अंतिम गंतव्य सर्वर के बीच पार किए गए प्रत्येक मध्यवर्ती राउटर (हॉप) के आईपी पते और विलंबता को सूचीबद्ध करता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which email protocol is specifically designed to synchronize mail folders across multiple devices, leaving the master emails stored safely on the server?",opts:["SMTP","POP3","IMAP","FTP"],ans:2,exp:"IMAP (Internet Message Access Protocol) operates on port 143 (or 993 securely). Unlike the older POP3 protocol which forcefully downloads and deletes emails from the server, IMAP maintains constant synchronization. Reading or moving an email on your phone instantly updates the server, reflecting the change identically on your laptop."},hi:{q:"कौन सा ईमेल प्रोटोकॉल विशेष रूप से कई उपकरणों में मेल फ़ोल्डरों को सिंक्रनाइज़ करने के लिए डिज़ाइन किया गया है, जिससे मास्टर ईमेल सर्वर पर सुरक्षित रूप से संग्रहीत रहते हैं?",opts:["SMTP","POP3","IMAP","FTP"],ans:2,exp:"IMAP (इंटरनेट मैसेज एक्सेस प्रोटोकॉल) पोर्ट 143 (या सुरक्षित रूप से 993) पर काम करता है। पुराने POP3 प्रोटोकॉल के विपरीत जो सर्वर से ईमेल डाउनलोड करता है और हटा देता है, IMAP निरंतर सिंक्रनाइज़ेशन बनाए रखता है। आपके फोन पर एक ईमेल पढ़ने से सर्वर तुरंत अपडेट हो जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which OSI layer is responsible for translating the logical IP address into a physical MAC address before placing the frame onto the network wire?",opts:["Application Layer","Network Layer","Data Link Layer","Physical Layer"],ans:2,exp:"The Data Link Layer (Layer 2) handles framing. Before handing data down to the Physical layer for wire transmission, it uses ARP (Address Resolution Protocol) cache data to stamp the exact source and destination physical MAC addresses onto the frame header, ensuring localized delivery across switches."},hi:{q:"नेटवर्क वायर पर फ्रेम रखने से पहले तार्किक IP पते (logical IP address) को भौतिक MAC पते (physical MAC address) में अनुवाद करने के लिए कौन सी OSI परत (layer) जिम्मेदार है?",opts:["एप्लिकेशन लेयर","नेटवर्क लेयर","डेटा लिंक लेयर (Data Link Layer)","फिजिकल लेयर"],ans:2,exp:"डेटा लिंक लेयर (लेयर 2) फ्रेमिंग को संभालती है। वायर ट्रांसमिशन के लिए डेटा को फिजिकल लेयर को सौंपने से पहले, यह फ्रेम हेडर पर सटीक स्रोत और गंतव्य फिजिकल मैक एड्रेस को स्टैंप करने के लिए ARP (एड्रेस रेजोल्यूशन प्रोटोकॉल) कैश डेटा का उपयोग करता है।"}},
{type:"mcq",diff:"medium",en:{q:"In a standard Class A IPv4 address, how many octets (bytes) are used to identify the Network portion?",opts:["1 octet","2 octets","3 octets","4 octets"],ans:0,exp:"In classic Class A networking, only the very first octet (8 bits) is dedicated to the Network ID, leaving an immense 24 bits (the remaining 3 octets) dedicated for assigning individual Host IDs. This design creates a very small number of networks but allows over 16 million hosts per network."},hi:{q:"एक मानक क्लास ए (Class A) IPv4 एड्रेस में, नेटवर्क भाग को पहचानने के लिए कितने ऑक्टेट (बाइट्स) का उपयोग किया जाता है?",opts:["1 ऑक्टेट (1 octet)","2 ऑक्टेट्स","3 ऑक्टेट्स","4 ऑक्टेट्स"],ans:0,exp:"क्लासिक क्लास ए नेटवर्किंग में, केवल पहला ऑक्टेट (8 बिट्स) नेटवर्क आईडी को समर्पित होता है, जिससे व्यक्तिगत होस्ट आईडी निर्दिष्ट करने के लिए 24 बिट्स (शेष 3 ऑक्टेट्स) समर्पित होते हैं। यह डिज़ाइन बहुत कम संख्या में नेटवर्क बनाता है लेकिन प्रति नेटवर्क 16 मिलियन से अधिक होस्ट की अनुमति देता है।"}},
{type:"mcq",diff:"medium",en:{q:"What type of guided transmission media provides the highest bandwidth and complete immunity to EMI (Electromagnetic Interference)?",opts:["Unshielded Twisted Pair","Coaxial Cable","Fiber Optic Cable","Microwave"],ans:2,exp:"Fiber Optic cables transmit data as pulses of light generated by lasers or LEDs, rather than electrical currents. Because light photons do not generate or interact with magnetic fields, fiber cables are 100% immune to Electromagnetic Interference (EMI), enabling massive bandwidths over extreme distances securely."},hi:{q:"किस प्रकार का निर्देशित ट्रांसमिशन मीडिया (guided transmission media) उच्चतम बैंडविड्थ और EMI (इलेक्ट्रोमैग्नेटिक इंटरफेरेंस) से पूर्ण प्रतिरक्षा प्रदान करता है?",opts:["अनशील्डेड ट्विस्टेड पेयर","समाक्षीय केबल (Coaxial Cable)","फाइबर ऑप्टिक केबल (Fiber Optic Cable)","माइक्रोवेव"],ans:2,exp:"फाइबर ऑप्टिक केबल विद्युत धाराओं के बजाय लेजर या एलईडी द्वारा उत्पन्न प्रकाश के दालों के रूप में डेटा संचारित करते हैं। चूँकि प्रकाश फोटॉन चुंबकीय क्षेत्र उत्पन्न नहीं करते हैं, इसलिए फाइबर केबल विद्युत चुम्बकीय हस्तक्षेप (EMI) से 100% सुरक्षित हैं, जो चरम दूरी पर विशाल बैंडविड्थ को सक्षम करते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"What is the primary function of a 'Bridge' in networking?",opts:["To connect a LAN to the global Internet","To connect and filter traffic between two separate LAN segments running the same protocol","To dynamically assign IP addresses","To translate domain names"],ans:1,exp:"A Bridge is a Layer 2 networking device. Its sole purpose is to intelligently divide a large, congested LAN into two smaller segments, or bridge two separate LANs. It inspects MAC addresses and filters traffic; it only forwards a frame across the bridge if the destination MAC lies on the opposite segment."},hi:{q:"नेटवर्किंग में 'ब्रिज' (Bridge) का प्राथमिक कार्य क्या है?",opts:["LAN को वैश्विक इंटरनेट से जोड़ने के लिए","एक ही प्रोटोकॉल चलाने वाले दो अलग-अलग LAN सेगमेंट के बीच ट्रैफ़िक को जोड़ने और फ़िल्टर करने के लिए","आईपी ​​पते (IP addresses) गतिशील रूप से निर्दिष्ट करने के लिए","डोमेन नाम का अनुवाद करने के लिए"],ans:1,exp:"एक ब्रिज एक लेयर 2 नेटवर्किंग डिवाइस है। इसका एकमात्र उद्देश्य एक बड़े, भीड़भाड़ वाले लैन को दो छोटे खंडों में विभाजित करना या दो अलग-अलग लैन को पाटना है। यह MAC पतों का निरीक्षण करता है और ट्रैफ़िक को फ़िल्टर करता है; यह केवल तभी ब्रिज के पार एक फ्रेम को आगे बढ़ाता है जब गंतव्य MAC विपरीत खंड पर हो।"}},
{type:"mcq",diff:"medium",en:{q:"Which of the following ports is associated with POP3 (Post Office Protocol version 3)?",opts:["25","110","143","80"],ans:1,exp:"POP3 is the legacy Application layer protocol used to download emails from a remote server to a local email client. It universally listens on TCP port 110 (or port 995 for encrypted SSL/TLS connections). Once downloaded via POP3, emails are typically deleted from the server."},hi:{q:"निम्नलिखित में से कौन सा पोर्ट POP3 (पोस्ट ऑफिस प्रोटोकॉल संस्करण 3) से जुड़ा है?",opts:["25","110","143","80"],ans:1,exp:"POP3 एक लिगेसी एप्लिकेशन लेयर प्रोटोकॉल है जिसका उपयोग रिमोट सर्वर से स्थानीय ईमेल क्लाइंट में ईमेल डाउनलोड करने के लिए किया जाता है। यह सार्वभौमिक रूप से TCP पोर्ट 110 (या एन्क्रिप्टेड SSL/TLS कनेक्शन के लिए पोर्ट 995) पर सुनता है। POP3 के माध्यम से डाउनलोड होने के बाद, ईमेल आमतौर पर सर्वर से हटा दिए जाते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"Which topology utilizes a single continuous cable forming a closed loop, where data travels in one direction passing through each computer?",opts:["Star Topology","Ring Topology","Mesh Topology","Bus Topology"],ans:1,exp:"In a Ring Topology, the network architecture strictly forms a closed, continuous physical circle. There are no terminated ends. Data frames travel sequentially around the ring in a unidirectional manner. Every workstation actively receives the token, checks the destination address, and passes it to the next node if it's not the recipient."},hi:{q:"कौन सी टोपोलॉजी एक बंद लूप बनाने वाली एकल निरंतर केबल का उपयोग करती है, जहां डेटा एक दिशा में यात्रा करता है और प्रत्येक कंप्यूटर से गुजरता है?",opts:["स्टार टोपोलॉजी","रिंग टोपोलॉजी (Ring Topology)","मेश टोपोलॉजी","बस टोपोलॉजी"],ans:1,exp:"रिंग टोपोलॉजी में, नेटवर्क आर्किटेक्चर कड़ाई से एक बंद, निरंतर भौतिक चक्र बनाता है। इसमें कोई समाप्त अंत नहीं है। डेटा फ़्रेम रिंग के चारों ओर एक दिशात्मक तरीके से क्रमिक रूप से यात्रा करते हैं। प्रत्येक कंप्यूटर टोकन प्राप्त करता है और जांचता है।"}},
{type:"mcq",diff:"medium",en:{q:"If a switch has 24 ports and 10 computers are connected to it, how many Collision Domains currently exist?",opts:["1","10","24","0"],ans:1,exp:"Unlike a hub which creates one massive shared collision domain, a Switch is an intelligent Layer 2 device that micro-segments the network. Every single active port on a switch acts as its own completely isolated Collision Domain. Since 10 computers are actively plugged in, there are 10 distinct, collision-free domains operating simultaneously."},hi:{q:"यदि किसी स्विच में 24 पोर्ट हैं और 10 कंप्यूटर उससे जुड़े हैं, तो वर्तमान में कितने कोलिजन डोमेन (Collision Domains) मौजूद हैं?",opts:["1","10","24","0"],ans:1,exp:"एक हब के विपरीत जो एक विशाल साझा कोलिजन डोमेन (Collision Domain) बनाता है, एक स्विच एक बुद्धिमान लेयर 2 डिवाइस है जो नेटवर्क को माइक्रो-सेगमेंट करता है। स्विच पर प्रत्येक सक्रिय पोर्ट अपने पूरी तरह से अलग कोलिजन डोमेन के रूप में कार्य करता है। चूंकि 10 कंप्यूटर प्लग इन हैं, इसलिए 10 डोमेन एक साथ काम कर रहे हैं।"}},
{type:"mcq",diff:"medium",en:{q:"Which command line utility is used to check the complete IP configuration, including MAC address and DNS servers, on a Windows computer?",opts:["ifconfig","ping -a","ipconfig /all","netstat"],ans:2,exp:"In the Windows OS environment, the 'ipconfig' command displays basic IP info. However, appending the '/all' switch ('ipconfig /all') forces the system to dump the comprehensive networking profile, detailing the physical MAC address, DHCP lease times, subnet masks, and designated DNS/Gateway servers for all network adapters."},hi:{q:"Windows कंप्यूटर पर मैक एड्रेस (MAC address) और डीएनएस सर्वर (DNS servers) सहित संपूर्ण आईपी कॉन्फ़िगरेशन की जांच करने के लिए किस कमांड लाइन उपयोगिता का उपयोग किया जाता है?",opts:["ifconfig","ping -a","ipconfig /all","netstat"],ans:2,exp:"विंडोज ओएस वातावरण में, 'ipconfig' कमांड बुनियादी आईपी जानकारी प्रदर्शित करता है। हालाँकि, '/all' स्विच ('ipconfig /all') को जोड़ने से सिस्टम व्यापक नेटवर्किंग प्रोफ़ाइल को डंप करने के लिए मजबूर करता है, जिसमें भौतिक मैक एड्रेस, सबनेट मास्क और डीएनएस सर्वर का विवरण होता है।"}},
{type:"mcq",diff:"medium",en:{q:"In standard Ethernet cabling, which category (Cat) of UTP cable is rated to reliably transmit Gigabit Ethernet (1000 Mbps) over 100 meters?",opts:["Cat 3","Cat 5","Cat 5e","Cat 2"],ans:2,exp:"While legacy Cat 5 was strictly limited to 100 Mbps (Fast Ethernet), 'Cat 5e' (Category 5 enhanced) implements stricter crosstalk specifications. This engineering improvement allows Cat 5e to reliably push 1 Gbps (1000 Mbps) Gigabit Ethernet speeds over the standard maximum cable length of 100 meters."},hi:{q:"मानक ईथरनेट केबलिंग में, UTP केबल की किस श्रेणी (Cat) को 100 मीटर से अधिक की दूरी पर गिगाबिट ईथरनेट (1000 Mbps) को मज़बूती से प्रसारित करने के लिए रेट किया गया है?",opts:["Cat 3","Cat 5","Cat 5e","Cat 2"],ans:2,exp:"जबकि विरासत Cat 5 सख्ती से 100 एमबीपीएस (फास्ट ईथरनेट) तक सीमित था, 'Cat 5e' (श्रेणी 5 एन्हांस्ड) सख्त क्रॉसस्टॉक विनिर्देशों को लागू करता है। यह सुधार Cat 5e को 100 मीटर की मानक अधिकतम केबल लंबाई पर 1 जीबीपीएस (1000 एमबीपीएस) गीगाबिट ईथरनेट गति को मज़बूती से धकेलने की अनुमति देता है।"}},
{type:"mcq",diff:"medium",en:{q:"What type of network architecture involves computers that share resources equally without relying on a dedicated central server?",opts:["Client-Server","Peer-to-Peer (P2P)","Hierarchical","Mainframe"],ans:1,exp:"In a Peer-to-Peer (P2P) network architecture, there is no centralized, authoritative server holding all files or managing security. Instead, every individual computer (node) functions simultaneously as both a client and a server, equally sharing files, printers, and processing power directly with one another."},hi:{q:"किस प्रकार के नेटवर्क आर्किटेक्चर में ऐसे कंप्यूटर शामिल होते हैं जो समर्पित केंद्रीय सर्वर पर निर्भर हुए बिना संसाधनों को समान रूप से साझा करते हैं?",opts:["क्लाइंट-सर्वर","पीयर-टू-पीयर (P2P - Peer-to-Peer)","हाइरार्किकल (Hierarchical)","मेनफ्रेम (Mainframe)"],ans:1,exp:"पीयर-टू-पीयर (P2P) नेटवर्क आर्किटेक्चर में, कोई केंद्रीकृत सर्वर नहीं होता है जो सभी फाइलों को रखता हो या सुरक्षा का प्रबंधन करता हो। इसके बजाय, प्रत्येक व्यक्तिगत कंप्यूटर (नोड) एक क्लाइंट और सर्वर दोनों के रूप में एक साथ कार्य करता है, फ़ाइलों, प्रिंटर और प्रसंस्करण शक्ति को सीधे एक दूसरे के साथ समान रूप से साझा करता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which of the following protocols is explicitly responsible for assigning dynamic IP addresses to devices?",opts:["HTTP","DNS","DHCP","SMTP"],ans:2,exp:"Dynamic Host Configuration Protocol (DHCP) uses a client-server architecture. When a device joins, it broadcasts a DHCP Discover packet. The DHCP server responds with a DHCP Offer, leasing the device a temporary IP address from its defined scope pool, eliminating IP conflicts and manual configuration errors."},hi:{q:"निम्नलिखित में से कौन सा प्रोटोकॉल स्पष्ट रूप से उपकरणों को गतिशील आईपी पते (dynamic IP addresses) निर्दिष्ट करने के लिए जिम्मेदार है?",opts:["HTTP","DNS","DHCP","SMTP"],ans:2,exp:"डायनामिक होस्ट कॉन्फ़िगरेशन प्रोटोकॉल (DHCP) क्लाइंट-सर्वर आर्किटेक्चर का उपयोग करता है। जब कोई उपकरण जुड़ता है, तो यह एक DHCP डिस्कवर पैकेट प्रसारित करता है। DHCP सर्वर डिवाइस को एक अस्थायी आईपी एड्रेस पट्टे पर देकर प्रतिक्रिया करता है, जिससे आईपी संघर्ष और मैन्युअल कॉन्फ़िगरेशन त्रुटियां समाप्त हो जाती हैं।"}},

// MEDIUM: 2 True/False
{type:"tf",diff:"medium",en:{q:"IPv6 was engineered using 128-bit hexadecimal addresses to overcome the imminent address exhaustion crisis of IPv4.",opts:["True","False"],ans:0,exp:"True. IPv4 uses 32-bit architecture, maxing out at roughly 4.3 billion addresses, which ran out due to the mobile and IoT boom. IPv6 utilizes an immense 128-bit architecture, creating an astronomically large pool of 340 undecillion addresses, represented using hexadecimal notation separated by colons."},hi:{q:"IPv6 को 128-बिट हेक्साडेसिमल पते (hexadecimal addresses) का उपयोग करके इंजीनियर किया गया था ताकि IPv4 के आसन्न पते की थकावट संकट को दूर किया जा सके।",opts:["सही","गलत"],ans:0,exp:"सही। IPv4 32-बिट आर्किटेक्चर का उपयोग करता है, जो मोबाइल और IoT बूम के कारण समाप्त हो गया। IPv6 एक विशाल 128-बिट आर्किटेक्चर का उपयोग करता है, जो 340 अनडेसिलियन पतों का खगोलीय रूप से बड़ा पूल बनाता है, जिसे कोलन (colons) द्वारा अलग किए गए हेक्साडेसिमल नोटेशन का उपयोग करके दर्शाया जाता है।"}},
{type:"tf",diff:"medium",en:{q:"A standard Hub reduces network collisions because it inspects MAC addresses before forwarding packets.",opts:["True","False"],ans:1,exp:"False. A Hub has no logical memory or MAC table. It operates purely electrically at Layer 1. When it receives a signal, it blindly broadcasts it out of every other port, creating one massive collision domain where only one device can transmit safely at a time."},hi:{q:"एक मानक हब (Hub) नेटवर्क टकराव (network collisions) को कम करता है क्योंकि यह पैकेट को अग्रेषित करने से पहले MAC पतों का निरीक्षण करता है।",opts:["सही","गलत"],ans:1,exp:"गलत। एक हब (Hub) में कोई तार्किक मेमोरी या MAC टेबल नहीं होती है। यह विशुद्ध रूप से लेयर 1 पर काम करता है। जब यह कोई सिग्नल प्राप्त करता है, तो यह हर दूसरे पोर्ट पर उसे प्रसारित (broadcast) करता है, जिससे एक बड़ा कोलिजन डोमेन बनता है जहां एक समय में केवल एक ही डिवाइस सुरक्षित रूप से संचारित कर सकता है।"}},

// ==========================================
// HARD: 28 MCQs
// ==========================================
{type:"mcq",diff:"hard",en:{q:"In the OSI model, Protocol Data Units (PDUs) are named differently at each layer. What is the PDU strictly called at the Data Link Layer?",opts:["Packet","Frame","Segment","Bit"],ans:1,exp:"Data encapsulation changes terminology per layer. At Layer 4 (Transport), data is divided into 'Segments'. At Layer 3 (Network), logical IP headers are added creating 'Packets'. Finally, at Layer 2 (Data Link), physical MAC headers and error-checking trailers are appended, encapsulating the data into structured 'Frames'."},hi:{q:"OSI मॉडल में, प्रत्येक लेयर पर प्रोटोकॉल डेटा यूनिट (PDUs) को अलग-अलग नाम दिया गया है। डेटा लिंक लेयर पर PDU को सख्ती से क्या कहा जाता है?",opts:["पैकेट (Packet)","फ्रेम (Frame)","सेगमेंट (Segment)","बिट (Bit)"],ans:1,exp:"लेयर 4 (ट्रांसपोर्ट) पर, डेटा को 'सेगमेंट' में विभाजित किया जाता है। लेयर 3 (नेटवर्क) में, तार्किक IP हेडर जोड़े जाते हैं जिससे 'पैकेट' बनते हैं। अंत में, लेयर 2 (डेटा लिंक) पर, भौतिक MAC हेडर और त्रुटि-जांच ट्रेलरों को जोड़ा जाता है, जो डेटा को संरचित 'फ्रेम' में घेरते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"A MAC address is mathematically represented by 48 bits. What specific globally managed identifier do the first 24 bits (3 bytes) represent?",opts:["The serial number of the PC","The OUI (Organizationally Unique Identifier) assigned to the hardware manufacturer","The IP subnet mask","The logical network routing protocol"],ans:1,exp:"The 48-bit MAC address is structurally divided in half. The IEEE globally manages the first 24 bits (3 bytes), known as the OUI (Organizationally Unique Identifier), and assigns them strictly to manufacturers (like Cisco, Apple, Intel). The vendor assigns the remaining 24 bits as a unique serial number for the specific NIC."},hi:{q:"एक MAC पता गणितीय रूप से 48 बिट्स द्वारा दर्शाया जाता है। पहले 24 बिट (3 बाइट्स) विश्व स्तर पर प्रबंधित किस विशिष्ट पहचानकर्ता का प्रतिनिधित्व करते हैं?",opts:["पीसी का सीरियल नंबर","हार्डवेयर निर्माता को सौंपा गया OUI (Organizationally Unique Identifier)","आईपी ​​सबनेट मास्क","तार्किक नेटवर्क राउटिंग प्रोटोकॉल"],ans:1,exp:"48-बिट MAC पता संरचनात्मक रूप से आधा विभाजित है। IEEE विश्व स्तर पर पहले 24 बिट्स (3 बाइट्स) का प्रबंधन करता है, जिसे OUI (ऑर्गेनाइजेशनली यूनीक आइडेंटिफायर) के रूप में जाना जाता है, और उन्हें निर्माताओं को सौंपता है। विक्रेता शेष 24 बिट्स को एक अद्वितीय सीरियल नंबर के रूप में निर्दिष्ट करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Under legacy classful IPv4 addressing architecture, which specific class is strictly reserved for global IP Multicasting groups (e.g., streaming video to multiple subscribers)?",opts:["Class B","Class C","Class D","Class E"],ans:2,exp:"The IANA strictly reserved the Class D IPv4 address space (spanning 224.0.0.0 through 239.255.255.255) explicitly for Multicasting. Unlike standard unicast traffic, multicast packets are delivered logically to a defined 'group' of receivers simultaneously, drastically reducing bandwidth for things like IPTV or routing protocol updates."},hi:{q:"विरासत क्लासफुल (classful) IPv4 एड्रेसिंग आर्किटेक्चर के तहत, कौन सी विशिष्ट श्रेणी वैश्विक आईपी मल्टीकास्टिंग समूहों (जैसे कई ग्राहकों के लिए स्ट्रीमिंग वीडियो) के लिए कड़ाई से आरक्षित है?",opts:["Class B","Class C","Class D","Class E"],ans:2,exp:"IANA ने मल्टीकास्टिंग (Multicasting) के लिए क्लास D IPv4 एड्रेस स्पेस (224.0.0.0 से 239.255.255.255 तक फैला हुआ) को सख्ती से आरक्षित किया है। मानक यूनिकास्ट ट्रैफ़िक के विपरीत, मल्टीकास्ट पैकेट एक साथ रिसीवर के परिभाषित 'समूह' को तार्किक रूप से वितरित किए जाते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"If a host is manually assigned the IP address 192.168.1.50 with a subnet mask of 255.255.255.0, what is the exact mathematical Network Address of this subnet?",opts:["192.168.1.50","192.168.1.0","192.168.1.255","192.168.0.0"],ans:1,exp:"To calculate the Network Address, the IP address and the Subnet Mask are processed using a binary bitwise AND operation. The 255s lock in the first three octets (192.168.1), while the 0 in the subnet mask zeroes out the host portion (50 becomes 0). Thus, the base network address is 192.168.1.0."},hi:{q:"यदि किसी होस्ट को 255.255.255.0 के सबनेट मास्क के साथ IP पता 192.168.1.50 मैन्युअल रूप से सौंपा गया है, तो इस सबनेट का सटीक गणितीय नेटवर्क एड्रेस (Network Address) क्या है?",opts:["192.168.1.50","192.168.1.0","192.168.1.255","192.168.0.0"],ans:1,exp:"नेटवर्क एड्रेस की गणना करने के लिए, IP एड्रेस और सबनेट मास्क को बाइनरी बिटवाइज़ AND ऑपरेशन का उपयोग करके संसाधित किया जाता है। 255s पहले तीन ऑक्टेट्स (192.168.1) में लॉक हो जाते हैं, जबकि सबनेट मास्क में 0 होस्ट भाग को शून्य कर देता है (50 0 हो जाता है)। इस प्रकार, नेटवर्क पता 192.168.1.0 है।"}},
{type:"mcq",diff:"hard",en:{q:"How does an interconnected network fundamentally handle a 'Broadcast Domain' when traversing a Router versus traversing a Switch?",opts:["Switches stop broadcasts; Routers forward broadcasts","Routers physically block Layer 2 broadcasts and segment broadcast domains; Switches blindly forward broadcasts out all ports (except the receiving port)","Both devices block broadcasts entirely","Neither device can block a broadcast"],ans:1,exp:"A Broadcast Domain is the logical boundary where a broadcast frame (MAC FF:FF:FF:FF:FF:FF) can reach. Layer 2 Switches flood broadcasts to all connected ports within a VLAN. Layer 3 Routers are specifically engineered to block broadcast packets, containing the noise and stopping broadcast storms from crossing into entirely different networks."},hi:{q:"एक राउटर (Router) को पार करने बनाम एक स्विच (Switch) को पार करने पर एक नेटवर्क मौलिक रूप से 'ब्रॉडकास्ट डोमेन' (Broadcast Domain) को कैसे संभालता है?",opts:["स्विच प्रसारण रोकते हैं; राउटर प्रसारण को आगे बढ़ाते हैं","राउटर भौतिक रूप से लेयर 2 प्रसारण को अवरुद्ध करते हैं और ब्रॉडकास्ट डोमेन को खंडित करते हैं; स्विच आँख बंद करके सभी पोर्ट पर प्रसारण को आगे बढ़ाते हैं","दोनों डिवाइस पूरी तरह से ब्रॉडकास्ट को रोकते हैं","कोई भी उपकरण ब्रॉडकास्ट को नहीं रोक सकता"],ans:1,exp:"एक ब्रॉडकास्ट डोमेन एक तार्किक सीमा है जहां एक ब्रॉडकास्ट फ्रेम पहुंच सकता है। लेयर 2 स्विच VLAN के भीतर सभी कनेक्टेड पोर्ट पर ब्रॉडकास्ट करते हैं। लेयर 3 राउटर विशेष रूप से ब्रॉडकास्ट पैकेट को ब्लॉक करने के लिए इंजीनियर किए गए हैं, जिससे ब्रॉडकास्ट डोमेन खंडित होता है।"}},
{type:"mcq",diff:"hard",en:{q:"In CIDR notation, what exact dotted-decimal subnet mask does a '/26' suffix represent?",opts:["255.255.255.0","255.255.255.128","255.255.255.192","255.255.255.224"],ans:2,exp:"A /26 prefix means exactly 26 contiguous binary bits are set to '1' for the network mask. This breaks down to 8+8+8+2 bits. The first three octets are 255.255.255. The fourth octet's first two bits are '11000000', which converts from binary to decimal as 128 + 64 = 192. Therefore, 255.255.255.192."},hi:{q:"CIDR नोटेशन में, '/26' प्रत्यय (suffix) किस सटीक डॉटेड-दशमलव सबनेट मास्क (dotted-decimal subnet mask) का प्रतिनिधित्व करता है?",opts:["255.255.255.0","255.255.255.128","255.255.255.192","255.255.255.224"],ans:2,exp:"/26 उपसर्ग का अर्थ है कि नेटवर्क मास्क के लिए ठीक 26 सन्निहित बाइनरी बिट्स '1' पर सेट हैं। यह 8+8+8+2 बिट्स में टूट जाता है। पहले तीन ऑक्टेट 255.255.255 हैं। चौथे ऑक्टेट के पहले दो बिट '11000000' हैं, जो बाइनरी से दशमलव में 128 + 64 = 192 के रूप में परिवर्तित होते हैं। इसलिए, 255.255.255.192 है।"}},
{type:"mcq",diff:"hard",en:{q:"Calculate the maximum number of usable host IP addresses available inside a standard /24 (Class C) subnet.",opts:["256","255","254","128"],ans:2,exp:"A /24 subnet mask leaves 8 bits exclusively for the host portion (32 bits total - 24 network bits = 8 host bits). Mathematically, 2^8 equals 256 total IP addresses. However, IP networking rules mandate subtracting 2 addresses (the Network Address containing all 0s, and the Broadcast Address containing all 1s), leaving exactly 254 usable IPs for devices."},hi:{q:"मानक /24 (Class C) सबनेट के अंदर उपलब्ध उपयोग करने योग्य (usable) होस्ट IP पतों की अधिकतम संख्या की गणना करें।",opts:["256","255","254","128"],ans:2,exp:"/24 सबनेट मास्क होस्ट भाग के लिए विशेष रूप से 8 बिट छोड़ता है। गणितीय रूप से, 2^8 256 कुल आईपी पतों के बराबर है। हालाँकि, IP नेटवर्किंग नियम 2 पतों को घटाना अनिवार्य करते हैं (सभी 0 वाले नेटवर्क एड्रेस, और सभी 1 वाले ब्रॉडकास्ट एड्रेस), जिससे ठीक 254 प्रयोग करने योग्य IP बचते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"Which legacy media access control protocol was engineered strictly for half-duplex Ethernet networks to sense the wire and detect data collisions?",opts:["CSMA/CA","CSMA/CD","Token Passing","BGP"],ans:1,exp:"Carrier Sense Multiple Access with Collision Detection (CSMA/CD) was the foundation of early Ethernet using Hubs. A NIC 'listened' to the wire before transmitting. If two NICs transmitted simultaneously, a physical voltage collision occurred. CSMA/CD detected this, sent a jam signal, and forced devices to wait a random backoff timer before retrying."},hi:{q:"वायर को महसूस करने और डेटा टकराव (data collisions) का पता लगाने के लिए कौन सा मीडिया एक्सेस कंट्रोल प्रोटोकॉल सख्ती से हाफ-डुप्लेक्स ईथरनेट नेटवर्क के लिए इंजीनियर किया गया था?",opts:["CSMA/CA","CSMA/CD","टोकन पासिंग (Token Passing)","BGP"],ans:1,exp:"टक्कर का पता लगाने के साथ कैरियर सेंस मल्टीपल एक्सेस (CSMA/CD) हब का उपयोग करने वाले शुरुआती ईथरनेट की नींव थी। एक एनआईसी ने संचारित करने से पहले तार को 'सुना'। यदि टकराव हुआ, तो CSMA/CD ने इसका पता लगाया, और पुन: प्रयास करने से पहले उपकरणों को एक यादृच्छिक बैकऑफ़ टाइमर की प्रतीक्षा करने के लिए मजबूर किया।"}},
{type:"mcq",diff:"hard",en:{q:"In the highly reliable TCP connection establishment process, what is the exact ordered sequence of the 3-way handshake?",opts:["SYN, ACK, SYN-ACK","SYN, SYN-ACK, ACK","ACK, SYN, SYN-ACK","SYN-ACK, SYN, ACK"],ans:1,exp:"To establish a reliable TCP socket connection, a strict 3-step synchronization occurs. 1) The Client sends a SYN (Synchronize) packet. 2) The Server receives it and replies with a SYN-ACK (Synchronize-Acknowledge). 3) Finally, the Client confirms receipt by sending an ACK (Acknowledge) packet, officially opening the connection for data payload transmission."},hi:{q:"अत्यधिक विश्वसनीय TCP कनेक्शन स्थापना प्रक्रिया में, 3-वे हैंडशेक (3-way handshake) का सटीक क्रम क्या है?",opts:["SYN, ACK, SYN-ACK","SYN, SYN-ACK, ACK","ACK, SYN, SYN-ACK","SYN-ACK, SYN, ACK"],ans:1,exp:"एक विश्वसनीय TCP सॉकेट कनेक्शन स्थापित करने के लिए, एक सख्त 3-चरणीय सिंक्रनाइज़ेशन होता है। 1) क्लाइंट एक SYN (Synchronize) पैकेट भेजता है। 2) सर्वर इसे प्राप्त करता है और SYN-ACK के साथ उत्तर देता है। 3) अंत में, क्लाइंट ACK (Acknowledge) पैकेट भेजकर कनेक्शन खोलता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which protocol does a host computer utilize to dynamically resolve a known logical IPv4 address into an unknown physical MAC address on a local network segment?",opts:["DNS","DHCP","ARP","RARP"],ans:2,exp:"ARP (Address Resolution Protocol) bridges Layer 3 (IP) to Layer 2 (MAC). When PC-A wants to send data to PC-B's known IP address but lacks the MAC address required for switch delivery, PC-A broadcasts an ARP Request ('Who has IP X?'). PC-B replies with a unicast ARP Reply providing its physical MAC address."},hi:{q:"एक होस्ट कंप्यूटर स्थानीय नेटवर्क सेगमेंट पर किसी ज्ञात तार्किक IPv4 पते को अज्ञात भौतिक MAC पते में गतिशील रूप से हल (resolve) करने के लिए किस प्रोटोकॉल का उपयोग करता है?",opts:["DNS","DHCP","ARP (Address Resolution Protocol)","RARP"],ans:2,exp:"ARP (एड्रेस रेजोल्यूशन प्रोटोकॉल) लेयर 3 (IP) को लेयर 2 (MAC) से पाटता है। जब किसी पीसी को ज्ञात आईपी पते पर डेटा भेजना होता है, लेकिन उसके पास मैक पता नहीं होता है, तो पीसी एक एआरपी अनुरोध ('किसके पास आईपी एक्स है?') प्रसारित करता है। लक्ष्य पीसी अपने मैक पते के साथ एआरपी रिप्लाई (ARP Reply) प्रदान करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Border Gateway Protocol (BGP) is the backbone routing protocol of the global Internet. How is it fundamentally classified?",opts:["Interior Gateway Protocol (IGP)","Link-State Protocol","Exterior Gateway Protocol (EGP)","Distance-Vector Protocol"],ans:2,exp:"BGP is an Exterior Gateway Protocol (EGP), specifically a Path-Vector protocol. Unlike OSPF or EIGRP which route traffic internally within a single enterprise (Autonomous System), BGP explicitly dictates how routing data is securely exchanged BETWEEN different giant Autonomous Systems (like major ISPs), forming the physical connective tissue of the global Internet."},hi:{q:"बॉर्डर गेटवे प्रोटोकॉल (BGP) वैश्विक इंटरनेट का बैकबोन राउटिंग प्रोटोकॉल है। इसे मौलिक रूप से कैसे वर्गीकृत किया गया है?",opts:["इंटीरियर गेटवे प्रोटोकॉल (IGP)","लिंक-स्टेट प्रोटोकॉल (Link-State Protocol)","एक्सटीरियर गेटवे प्रोटोकॉल (EGP - Exterior Gateway Protocol)","डिस्टेंस-वेक्टर प्रोटोकॉल"],ans:2,exp:"BGP एक एक्सटीरियर गेटवे प्रोटोकॉल (EGP) है। ओएसपीएफ (OSPF) के विपरीत जो एक उद्यम (स्वायत्त प्रणाली) के भीतर आंतरिक रूप से यातायात को रूट करते हैं, बीजीपी स्पष्ट रूप से निर्धारित करता है कि वैश्विक इंटरनेट बनाने वाले विभिन्न विशाल स्वायत्त प्रणालियों (प्रमुख आईएसपी की तरह) के बीच डेटा का आदान-प्रदान कैसे किया जाता है।"}},
{type:"mcq",diff:"hard",en:{q:"In large switched Ethernet networks, what is the critical architectural purpose of implementing the Spanning Tree Protocol (STP)?",opts:["To assign IP addresses to switches","To completely prevent disastrous Layer 2 broadcast storms caused by redundant physical cable loops","To encrypt data passing between switches","To boost the speed of gigabit ports"],ans:1,exp:"Network engineers physically wire redundant cable links between switches to ensure uptime if a cable snaps. However, Ethernet frames have no TTL (Time To Live). Redundant paths cause Layer 2 broadcast frames to loop infinitely, melting network switches. Spanning Tree Protocol (STP) mathematically detects these physical loops and logically blocks redundant ports to guarantee a loop-free topology."},hi:{q:"बड़े स्विच्ड ईथरनेट नेटवर्क में, स्पैनिंग ट्री प्रोटोकॉल (STP - Spanning Tree Protocol) को लागू करने का महत्वपूर्ण वास्तुशिल्प उद्देश्य क्या है?",opts:["स्विच को IP पते निर्दिष्ट करने के लिए","अनावश्यक भौतिक केबल लूप के कारण होने वाले विनाशकारी लेयर 2 ब्रॉडकास्ट तूफानों को पूरी तरह से रोकने के लिए","स्विच के बीच गुजरने वाले डेटा को एन्क्रिप्ट करने के लिए","गीगाबिट पोर्ट की गति को बढ़ावा देने के लिए"],ans:1,exp:"यदि केबल टूट जाती है तो अपटाइम सुनिश्चित करने के लिए इंजीनियर स्विच के बीच निरर्थक केबल लिंक जोड़ते हैं। हालाँकि, निरर्थक पथ लेयर 2 प्रसारण फ्रेम को असीम रूप से लूप करने का कारण बनते हैं। स्पैनिंग ट्री प्रोटोकॉल (STP) तार्किक रूप से लूप-मुक्त टोपोलॉजी की गारंटी देने के लिए अनावश्यक पोर्ट को ब्लॉक करता है।"}},
{type:"mcq",diff:"hard",en:{q:"What critical function does Network Address Translation (NAT) perform on a standard home broadband router?",opts:["It blocks viruses from downloading","It translates an entire private, internal IP subnet (like 192.168.x.x) into a single, routable public IP address assigned by the ISP to access the Internet","It translates IPv4 into IPv6","It translates MAC addresses into IP addresses"],ans:1,exp:"Because internal private IP addresses (RFC 1918) are strictly non-routable on the global internet, a router uses NAT (specifically PAT - Port Address Translation) to rewrite the source IP header of outgoing packets. It translates hundreds of internal private IPs into the one single public IP address assigned by the modem, conserving the IPv4 address space."},hi:{q:"एक मानक होम ब्रॉडबैंड राउटर पर नेटवर्क एड्रेस ट्रांसलेशन (NAT) कौन सा महत्वपूर्ण कार्य करता है?",opts:["यह वायरस को डाउनलोड होने से रोकता है","यह इंटरनेट तक पहुंचने के लिए ISP द्वारा निर्दिष्ट एक एकल, रूट करने योग्य सार्वजनिक IP पते में एक संपूर्ण निजी, आंतरिक IP सबनेट का अनुवाद करता है","यह IPv4 का IPv6 में अनुवाद करता है","यह MAC पतों का IP पतों में अनुवाद करता है"],ans:1,exp:"चूंकि आंतरिक निजी आईपी पते (RFC 1918) वैश्विक इंटरनेट पर रूट करने योग्य नहीं हैं, इसलिए राउटर NAT (नेटवर्क एड्रेस ट्रांसलेशन) का उपयोग करता है। यह एक सार्वजनिक आईपी पते में सैकड़ों आंतरिक निजी आईपी का अनुवाद करता है, जो IPv4 एड्रेस स्पेस को संरक्षित करता है।"}},
{type:"mcq",diff:"hard",en:{q:"In the modernized IPv6 protocol, what is the exact highly-compressed hexadecimal format of the localhost loopback address (equivalent to 127.0.0.1 in IPv4)?",opts:["0:0:0:0:0:0:0:1","::1","127::1","FE80::1"],ans:1,exp:"IPv6 utilizes 128-bit addresses. The loopback address consists of 127 zero bits followed by a single 1 bit (0000:0000:0000:0000:0000:0000:0000:0001). Under standard IPv6 zero-compression rules, contiguous blocks of all-zero hextets can be completely replaced by a double colon exactly once, elegantly condensing the address to simply '::1'."},hi:{q:"आधुनिक IPv6 प्रोटोकॉल में, लोकेलहोस्ट लूपबैक पते का सटीक अत्यधिक-संपीड़ित हेक्साडेसिमल प्रारूप क्या है (जो IPv4 में 127.0.0.1 के बराबर है)?",opts:["0:0:0:0:0:0:0:1","::1","127::1","FE80::1"],ans:1,exp:"IPv6 128-बिट पतों का उपयोग करता है। लूपबैक पते में 127 शून्य बिट होते हैं जिसके बाद एकल 1 बिट होता है। मानक IPv6 शून्य-संपीड़न नियमों के तहत, ऑल-शून्य हेक्सटेट्स के सन्निहित ब्लॉकों को पूरी तरह से एक डबल कोलन द्वारा प्रतिस्थापित किया जा सकता है, पते को '::1' में संक्षिप्त किया जा सकता है।"}},
{type:"mcq",diff:"hard",en:{q:"In strict network terminology regarding the Transport Layer, what are the Protocol Data Units (PDUs) produced specifically by TCP and UDP called?",opts:["Frames and Packets","Segments (TCP) and Datagrams (UDP)","Bits and Bytes","Windows and Sockets"],ans:1,exp:"Encapsulation nomenclature is highly precise. When the Transport layer processes data, TCP chops the data stream and adds its highly reliable sequencing header, creating a PDU strictly referred to as a 'Segment'. Conversely, UDP adds its lightweight, connectionless header, creating a PDU formally known as a 'Datagram'."},hi:{q:"ट्रांसपोर्ट लेयर के संबंध में सख्त नेटवर्क शब्दावली में, विशेष रूप से TCP और UDP द्वारा उत्पादित प्रोटोकॉल डेटा यूनिट्स (PDUs) को क्या कहा जाता है?",opts:["फ्रेम और पैकेट","सेगमेंट (TCP) और डेटाग्राम (UDP)","बिट्स और बाइट्स","विंडोज और सॉकेट्स"],ans:1,exp:"एनकैप्सुलेशन नामकरण अत्यधिक सटीक है। ट्रांसपोर्ट लेयर में, TCP डेटा स्ट्रीम को काटता है और अपना हेडर जोड़ता है, जिससे एक PDU बनता है जिसे कड़ाई से 'सेगमेंट' कहा जाता है। इसके विपरीत, UDP अपना हल्का, कनेक्शन रहित हेडर जोड़ता है, एक PDU बनाता है जिसे औपचारिक रूप से 'डेटाग्राम' कहा जाता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which cryptographic network protocol is explicitly engineered to replace the highly insecure Telnet protocol, operating universally on TCP port 22?",opts:["SSL","FTP","SSH (Secure Shell)","IPsec"],ans:2,exp:"Telnet sends remote administrative commands and passwords in completely readable plain text, vulnerable to packet sniffing. SSH (Secure Shell) operates on port 22 and entirely replaced Telnet by utilizing strong public-key cryptography to tunnel secure, encrypted command-line access into remote servers over unsecured public networks."},hi:{q:"कौन सा क्रिप्टोग्राफ़िक नेटवर्क प्रोटोकॉल स्पष्ट रूप से अत्यधिक असुरक्षित टेलनेट (Telnet) प्रोटोकॉल को बदलने के लिए इंजीनियर किया गया है, जो सार्वभौमिक रूप से TCP पोर्ट 22 पर काम कर रहा है?",opts:["SSL","FTP","SSH (Secure Shell)","IPsec"],ans:2,exp:"टेलनेट दूरस्थ प्रशासनिक कमांड और पासवर्ड पूरी तरह से पठनीय सादे पाठ में भेजता है, जो स्निफिंग (sniffing) की चपेट में है। SSH (सिक्योर शेल) पोर्ट 22 पर काम करता है और सार्वजनिक नेटवर्क पर रिमोट सर्वर तक सुरक्षित, एन्क्रिप्टेड कमांड-लाइन एक्सेस को टनल करने के लिए मजबूत क्रिप्टोग्राफी का उपयोग करके टेलनेट को पूरी तरह से बदल देता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which foundational service heavily relies on UDP Port 53 to facilitate its high-speed, connectionless query resolution architecture?",opts:["DHCP","DNS (Domain Name System)","SNMP","HTTP"],ans:1,exp:"The Domain Name System (DNS) is fundamentally architected to use UDP port 53 for standard client query resolution (converting www.google.com to an IP). Because UDP eliminates the heavy overhead of the TCP 3-way handshake, DNS queries occur in milliseconds. (DNS does use TCP 53 strictly for heavy zone transfers between massive servers)."},hi:{q:"कौन सी मूलभूत सेवा अपनी उच्च गति, कनेक्शन रहित क्वेरी रिज़ॉल्यूशन आर्किटेक्चर की सुविधा के लिए मुख्य रूप से UDP पोर्ट 53 पर निर्भर करती है?",opts:["DHCP","DNS (Domain Name System)","SNMP","HTTP"],ans:1,exp:"डोमेन नेम सिस्टम (DNS) मूल रूप से मानक क्लाइंट क्वेरी रिज़ॉल्यूशन के लिए UDP पोर्ट 53 का उपयोग करने के लिए तैयार किया गया है। चूंकि UDP TCP 3-वे हैंडशेक के भारी ओवरहेड को समाप्त कर देता है, DNS प्रश्न मिलीसेकंड में होते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"Which conceptual mechanism occurring strictly at the OSI Transport Layer allows a single computer IP address to simultaneously establish separate connections to a web browser, an email client, and a game server?",opts:["Encapsulation","Routing","Multiplexing (using Port Numbers)","Subnetting"],ans:2,exp:"Multiplexing is the mechanism where the Transport layer uses unique 16-bit Port Numbers (e.g., 80, 443, 25) to differentiate multiple distinct software application streams. This allows a single physical network link and a single IP address to simultaneously process hundreds of interleaved data streams without mixing them up."},hi:{q:"कड़ाई से OSI ट्रांसपोर्ट लेयर पर होने वाला कौन सा वैचारिक तंत्र एक एकल कंप्यूटर IP पते को एक साथ वेब ब्राउज़र, एक ईमेल क्लाइंट और गेम सर्वर से अलग कनेक्शन स्थापित करने की अनुमति देता है?",opts:["एनकैप्सुलेशन (Encapsulation)","राउटिंग (Routing)","मल्टीप्लेक्सिंग (पोर्ट नंबरों का उपयोग करके) (Multiplexing)","सबनेटिंग (Subnetting)"],ans:2,exp:"मल्टीप्लेक्सिंग वह तंत्र है जहां ट्रांसपोर्ट लेयर कई अलग-अलग सॉफ़्टवेयर एप्लिकेशन स्ट्रीम को अलग करने के लिए अद्वितीय 16-बिट पोर्ट नंबरों का उपयोग करती है। यह एक एकल भौतिक नेटवर्क लिंक और एक एकल आईपी पते को एक साथ सैकड़ों डेटा स्ट्रीम को बिना मिलाए संसाधित करने की अनुमति देता है।"}},
{type:"mcq",diff:"hard",en:{q:"If a Windows workstation fails entirely to reach a DHCP server, its operating system automatically invokes APIPA. What exact IP subnet range defines an APIPA address?",opts:["10.0.0.0/8","192.168.0.0/16","169.254.0.0/16","172.16.0.0/12"],ans:2,exp:"Automatic Private IP Addressing (APIPA) is an OS fail-safe mechanism. If DHCP discovery times out, Windows immediately self-assigns a random IP strictly from the Microsoft-reserved 169.254.x.x range (with a 255.255.0.0 mask). This ensures minimal link-local communication with other failed devices, but mathematically prevents routing out to the internet."},hi:{q:"यदि कोई Windows वर्कस्टेशन DHCP सर्वर तक पहुँचने में पूरी तरह विफल हो जाता है, तो इसका ऑपरेटिंग सिस्टम स्वचालित रूप से APIPA लागू करता है। APIPA एड्रेस किस IP सबनेट रेंज को परिभाषित करता है?",opts:["10.0.0.0/8","192.168.0.0/16","169.254.0.0/16","172.16.0.0/12"],ans:2,exp:"ऑटोमैटिक प्राइवेट आईपी एड्रेसिंग (APIPA) एक ओएस फेल-सेफ मैकेनिज्म है। यदि DHCP डिस्कवरी का समय समाप्त हो जाता है, तो Windows तुरंत Microsoft-आरक्षित 169.254.x.x श्रेणी से एक यादृच्छिक IP को स्व-असाइन करता है। यह अन्य विफल उपकरणों के साथ संचार सुनिश्चित करता है, लेकिन इंटरनेट से जुड़ने से रोकता है।"}},
{type:"mcq",diff:"hard",en:{q:"What is the primary physical and optical difference between Single-Mode Fiber (SMF) and Multi-Mode Fiber (MMF) cables?",opts:["SMF carries electrical signals; MMF carries light pulses","SMF uses a microscopically thin core (approx 9 microns) to transmit a single straight laser beam over immense distances (WAN); MMF uses a wider core allowing multiple light modes to bounce, utilized for shorter LAN distances","MMF is made of copper, SMF is made of glass","SMF is used for Wi-Fi antennas"],ans:1,exp:"Core diameter dictates the physics of the fiber. Single-Mode Fiber has an incredibly narrow glass core (8-10 microns), forcing a highly focused laser light to travel straight without bouncing (dispersion), achieving distances of dozens of kilometers. Multi-Mode has a wider core (50-62.5 microns) where LED light bounces at angles, limiting it to short LAN runs."},hi:{q:"सिंगल-मोड फाइबर (SMF) और मल्टी-मोड फाइबर (MMF) केबलों के बीच प्राथमिक भौतिक और ऑप्टिकल अंतर क्या है?",opts:["SMF विद्युत संकेत ले जाता है; MMF प्रकाश ले जाता है","SMF भारी दूरी पर लेजर बीम को प्रसारित करने के लिए एक पतले कोर का उपयोग करता है; MMF व्यापक कोर का उपयोग करता है, जिसका उपयोग छोटी LAN दूरी के लिए किया जाता है","MMF तांबे से बना है, SMF कांच से बना है","SMF का उपयोग Wi-Fi एंटेना के लिए किया जाता है"],ans:1,exp:"कोर व्यास फाइबर की भौतिकी को निर्धारित करता है। सिंगल-मोड फाइबर (SMF) में अविश्वसनीय रूप से संकीर्ण ग्लास कोर होता है, जो बिना उछलने (बिखरने) के सीधे यात्रा करने के लिए अत्यधिक केंद्रित लेजर प्रकाश को मजबूर करता है, जिससे किलोमीटर की दूरी प्राप्त होती है। मल्टी-मोड में एक विस्तृत कोर होता है जो इसे छोटे लैन रन तक सीमित करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Frame Relay, X.25, and ATM (Asynchronous Transfer Mode) are historical networking technologies classified fundamentally under which telecommunications category?",opts:["Circuit-Switched Networks","Packet-Switched WAN Technologies","Wireless PANs","Token Ring LANs"],ans:1,exp:"Instead of establishing a dedicated, continuous electrical circuit like a classic telephone call (Circuit Switching), technologies like X.25 and Frame Relay broke data into individual blocks (Packets or Frames). These packets were fired into an ISP cloud, sharing bandwidth with other customers, creating highly cost-effective Packet-Switched Wide Area Networks."},hi:{q:"फ्रेम रिले, X.25, और ATM (Asynchronous Transfer Mode) ऐतिहासिक नेटवर्किंग प्रौद्योगिकियां हैं जिन्हें मूल रूप से किस दूरसंचार श्रेणी के तहत वर्गीकृत किया गया है?",opts:["सर्किट-स्विच्ड नेटवर्क (Circuit-Switched Networks)","पैकेट-स्विच्ड वैन टेक्नोलॉजीज (Packet-Switched WAN Technologies)","वायरलेस PAN","टोकन रिंग LAN"],ans:1,exp:"क्लासिक टेलीफोन कॉल (सर्किट स्विचिंग) की तरह एक समर्पित, निरंतर विद्युत सर्किट स्थापित करने के बजाय, X.25 और फ्रेम रिले जैसी तकनीकों ने डेटा को अलग-अलग ब्लॉकों (पैकेट या फ़्रेम) में तोड़ दिया। ये पैकेट-स्विच्ड वाइड एरिया नेटवर्क बनाने वाली तकनीके हैं।"}},
{type:"mcq",diff:"hard",en:{q:"Which modern IEEE 802.11 Wi-Fi security protocol introduced Simultaneous Authentication of Equals (SAE) to actively defeat offline dictionary and brute-force password attacks?",opts:["WEP","WPA","WPA2","WPA3"],ans:3,exp:"Released by the Wi-Fi Alliance, WPA3 entirely replaced the vulnerable Pre-Shared Key (PSK) 4-way handshake found in WPA2. By implementing the cryptographic Simultaneous Authentication of Equals (SAE) protocol, WPA3 makes it mathematically impossible for hackers to capture wireless frames and crack the Wi-Fi password offline using massive dictionary lists."},hi:{q:"किस आधुनिक IEEE 802.11 वाई-फाई सुरक्षा प्रोटोकॉल ने ऑफ़लाइन डिक्शनरी और ब्रूट-फोर्स पासवर्ड हमलों (brute-force attacks) को सक्रिय रूप से हराने के लिए SAE (Simultaneous Authentication of Equals) की शुरुआत की?",opts:["WEP","WPA","WPA2","WPA3"],ans:3,exp:"वाई-फाई एलायंस द्वारा जारी, WPA3 ने पूरी तरह से WPA2 में पाए जाने वाले कमजोर प्री-शेयर्ड की (PSK) 4-वे हैंडशेक को बदल दिया। एसएई (SAE) प्रोटोकॉल को लागू करके, डब्ल्यूपीए 3 हैकर्स के लिए वायरलेस फ्रेम को पकड़ना और विशाल शब्दकोश सूचियों का उपयोग करके वाई-फाई पासवर्ड को ऑफ़लाइन क्रैक करना गणितीय रूप से असंभव बना देता है।"}},
{type:"mcq",diff:"hard",en:{q:"In enterprise switching, what is the exact architectural purpose of a VLAN (Virtual LAN)?",opts:["To increase the physical speed of copper cables","To logically divide a single physical Layer 2 switch into multiple distinct, isolated broadcast domains via software configuration","To connect to cellular networks","To convert analog signals to digital"],ans:1,exp:"VLANs completely break physical geography constraints. A network administrator can take a massive 48-port switch and assign ports 1-10 to VLAN 10 (HR) and ports 11-20 to VLAN 20 (IT). The switch logically isolates these groups. An ARP broadcast from an HR PC will never reach an IT PC, massively improving security and broadcast traffic control."},hi:{q:"एंटरप्राइज़ स्विचिंग में, VLAN (Virtual LAN) का सटीक वास्तुशिल्प उद्देश्य क्या है?",opts:["तांबे के केबलों की भौतिक गति बढ़ाने के लिए","सॉफ़्टवेयर कॉन्फ़िगरेशन के माध्यम से एक भौतिक लेयर 2 स्विच को तार्किक रूप से कई अलग, पृथक ब्रॉडकास्ट डोमेन में विभाजित करने के लिए","सेलुलर नेटवर्क से कनेक्ट करने के लिए","एनालॉग सिग्नल को डिजिटल में बदलने के लिए"],ans:1,exp:"VLAN भौतिक भूगोल की बाधाओं को पूरी तरह से तोड़ देते हैं। एक नेटवर्क एडमिनिस्ट्रेटर 48-पोर्ट स्विच ले सकता है और VLAN 10 (HR) और VLAN 20 (IT) को पोर्ट असाइन कर सकता है। स्विच तार्किक रूप से इन समूहों को अलग करता है, जिससे सुरक्षा और ब्रॉडकास्ट ट्रैफ़िक नियंत्रण में व्यापक सुधार होता है।"}},
{type:"mcq",diff:"hard",en:{q:"Without utilizing an intelligent Auto-MDIX switch port, what specific physical wiring configuration must be used in a UTP cable to connect two identical Layer 2 Switches directly together?",opts:["Rollover Cable","Straight-Through Cable","Crossover Cable","Console Cable"],ans:2,exp:"Before modern Auto-MDIX technology, connecting 'like' devices (Switch-to-Switch, Router-to-Router, or PC-to-PC) required a Crossover Cable. Because both switches transmit on pins 1 and 2, a straight-through cable causes their signals to physically collide. A Crossover cable physically crosses the transmit and receive wire pairs inside the RJ45 jacket to solve this."},hi:{q:"एक बुद्धिमान Auto-MDIX स्विच पोर्ट का उपयोग किए बिना, दो समान लेयर 2 स्विच को एक साथ जोड़ने के लिए UTP केबल में किस विशिष्ट भौतिक वायरिंग कॉन्फ़िगरेशन का उपयोग किया जाना चाहिए?",opts:["रोलओवर केबल (Rollover Cable)","स्ट्रेट-थ्रू केबल (Straight-Through Cable)","क्रॉसओवर केबल (Crossover Cable)","कंसोल केबल (Console Cable)"],ans:2,exp:"आधुनिक ऑटो-MDIX तकनीक से पहले, 'समान' उपकरणों (स्विच-टू-स्विच, राउटर-टू-राउटर, या पीसी-टू-पीसी) को जोड़ने के लिए क्रॉसओवर केबल (Crossover Cable) की आवश्यकता होती थी। एक क्रॉसओवर केबल इस समस्या को हल करने के लिए RJ45 जैकेट के अंदर ट्रांसमिट और रिसीव वायर जोड़े को भौतिक रूप से पार करता है।"}},
{type:"mcq",diff:"hard",en:{q:"In the highly specific IEEE 802 standard naming conventions, what exact technologies do 802.3 and 802.11 define respectively?",opts:["802.3 is Token Ring; 802.11 is Bluetooth","802.3 is wired Ethernet (CSMA/CD); 802.11 is Wireless LAN / Wi-Fi (CSMA/CA)","802.3 is Fiber Optics; 802.11 is TCP/IP","802.3 is IPv4; 802.11 is IPv6"],ans:1,exp:"The IEEE 802 committee meticulously standardizes Layer 1 and Layer 2 protocols. The 802.3 working group mathematically defines the specifications for wired Ethernet cables, signaling, and MAC framing. The 802.11 working group specifically defines the radio wave modulation and framing rules for Wireless LANs, globally marketed under the trademark 'Wi-Fi'."},hi:{q:"अत्यधिक विशिष्ट IEEE 802 मानक नामकरण सम्मेलनों में, 802.3 और 802.11 क्रमशः किन सटीक तकनीकों को परिभाषित करते हैं?",opts:["802.3 टोकन रिंग है; 802.11 ब्लूटूथ है","802.3 वायर्ड ईथरनेट (CSMA/CD) है; 802.11 वायरलेस लैन / वाई-फाई (CSMA/CA) है","802.3 फाइबर ऑप्टिक्स है; 802.11 TCP/IP है","802.3 IPv4 है; 802.11 IPv6 है"],ans:1,exp:"IEEE 802 समिति सावधानीपूर्वक लेयर 1 और लेयर 2 प्रोटोकॉल को मानकीकृत करती है। 802.3 वायर्ड ईथरनेट केबल, सिग्नलिंग और मैक फ्रेमिंग के विनिर्देशों को गणितीय रूप से परिभाषित करता है। 802.11 वायरलेस लैन (Wi-Fi) के लिए रेडियो तरंग मॉड्यूलेशन और फ्रेमिंग नियमों को परिभाषित करता है।"}},
{type:"mcq",diff:"hard",en:{q:"What mathematical operation does a computer's OS perform using the Subnet Mask and the destination IP address to determine if a packet belongs on the Local LAN or needs to be forwarded to the Default Gateway?",opts:["Binary Addition","Binary XOR (Exclusive OR)","Binary AND operation","Hexadecimal Subtraction"],ans:2,exp:"The networking stack strictly uses the Bitwise AND logical operation. The OS takes its own IP and ANDs it with its Subnet Mask to find its Local Network ID. It then takes the Destination IP of the packet and ANDs it with the same mask. If the two resulting Network IDs perfectly match, the packet is kept local via MAC address. If they differ, it is forcefully fired to the Router's Gateway IP."},hi:{q:"यह निर्धारित करने के लिए कि कोई पैकेट स्थानीय लैन से संबंधित है या डिफ़ॉल्ट गेटवे पर अग्रेषित करने की आवश्यकता है, कंप्यूटर का OS सबनेट मास्क और गंतव्य IP पते का उपयोग करके कौन सा गणितीय संचालन करता है?",opts:["बाइनरी एडिशन (Binary Addition)","बाइनरी XOR (एक्सक्लूसिव OR)","बाइनरी AND ऑपरेशन (Binary AND operation)","हेक्साडेसिमल घटाव"],ans:2,exp:"नेटवर्किंग स्टैक सख्ती से बिटवाइज़ AND (Bitwise AND) लॉजिकल ऑपरेशन का उपयोग करता है। OS अपनी स्वयं की IP लेता है और अपना स्थानीय नेटवर्क ID खोजने के लिए अपने सबनेट मास्क के साथ इसे AND करता है। यदि दोनों परिणामी नेटवर्क ID पूरी तरह से मेल खाते हैं, तो पैकेट MAC पते के माध्यम से स्थानीय रखा जाता है। यदि वे भिन्न होते हैं, तो इसे राउटर पर भेज दिया जाता है।"}},
{type:"mcq",diff:"hard",en:{q:"A network administrator wants to utilize a private IP Class B address space for an internal enterprise network. What exact IP range must be used to comply with RFC 1918?",opts:["10.0.0.0 to 10.255.255.255","172.16.0.0 to 172.31.255.255","192.168.0.0 to 192.168.255.255","224.0.0.0 to 239.255.255.255"],ans:1,exp:"RFC 1918 dictates specific blocks of IPs that are guaranteed never to be routed on the public internet, acting purely as internal IDs. The Class A private block is 10.x.x.x. The Class B private block strictly spans 172.16.0.0 through 172.31.255.255. The Class C private block is 192.168.x.x."},hi:{q:"एक नेटवर्क एडमिनिस्ट्रेटर आंतरिक एंटरप्राइज़ नेटवर्क के लिए एक निजी IP क्लास B (Class B) एड्रेस स्पेस का उपयोग करना चाहता है। RFC 1918 का अनुपालन करने के लिए किस सटीक IP श्रेणी का उपयोग किया जाना चाहिए?",opts:["10.0.0.0 से 10.255.255.255","172.16.0.0 से 172.31.255.255","192.168.0.0 से 192.168.255.255","224.0.0.0 से 239.255.255.255"],ans:1,exp:"RFC 1918 IP के विशिष्ट ब्लॉकों को निर्धारित करता है जिन्हें सार्वजनिक इंटरनेट पर रूट न करने की गारंटी दी जाती है। क्लास A निजी ब्लॉक 10.x.x.x है। क्लास B निजी ब्लॉक सख्ती से 172.16.0.0 से 172.31.255.255 तक फैला है। क्लास C निजी ब्लॉक 192.168.x.x है।"}},
{type:"mcq",diff:"hard",en:{q:"Which highly specific networking port is permanently assigned by IANA for establishing remote secure HTTPS administration panels and standard TLS encrypted web traffic?",opts:["UDP Port 80","TCP Port 443","TCP Port 23","TCP Port 3389"],ans:1,exp:"TCP port 443 is the absolute bedrock of modern web security. Whenever a browser navigates to 'https://', it mathematically forces a TCP connection solely to Port 443 on the remote server. The server then initiates the TLS/SSL cryptographic handshake over this port, generating symmetric session keys to perfectly encrypt the data payload."},hi:{q:"रिमोट सुरक्षित HTTPS प्रशासन पैनल और मानक TLS एन्क्रिप्टेड वेब ट्रैफ़िक स्थापित करने के लिए IANA द्वारा स्थायी रूप से कौन सा अत्यधिक विशिष्ट नेटवर्किंग पोर्ट निर्दिष्ट किया गया है?",opts:["UDP Port 80","TCP Port 443","TCP Port 23","TCP Port 3389"],ans:1,exp:"TCP पोर्ट 443 आधुनिक वेब सुरक्षा का पूर्ण आधार है। जब भी कोई ब्राउज़र 'https://' पर नेविगेट करता है, तो यह गणितीय रूप से रिमोट सर्वर पर केवल पोर्ट 443 से TCP कनेक्शन को बाध्य करता है। इसके बाद सर्वर इस पोर्ट पर TLS/SSL क्रिप्टोग्राफ़िक हैंडशेक शुरू करता है, जिससे डेटा को एन्क्रिप्ट किया जा सके।"}},

// HARD: 2 True/False
{type:"tf",diff:"hard",en:{q:"In TCP/IP routing architecture, a 'Default Gateway' IP address is absolutely required for a host computer to communicate with other hosts located on completely different logical subnets.",opts:["True","False"],ans:0,exp:"True. If a computer's binary ANDing process determines a destination IP is outside its own subnet mask range, it lacks the Layer 2 MAC capability to reach it directly. It must unconditionally forward the packet to its configured Default Gateway (the nearest Router interface) which possesses the routing tables necessary to navigate external networks."},hi:{q:"TCP/IP राउटिंग आर्किटेक्चर में, पूरी तरह से अलग लॉजिकल सबनेट पर स्थित अन्य होस्ट के साथ संवाद करने के लिए होस्ट कंप्यूटर के लिए 'डिफ़ॉल्ट गेटवे' (Default Gateway) IP पता बिल्कुल आवश्यक है।",opts:["सही","गलत"],ans:0,exp:"सही। यदि किसी कंप्यूटर की बाइनरी एंडिंग प्रक्रिया यह निर्धारित करती है कि गंतव्य IP इसके अपने सबनेट मास्क रेंज से बाहर है, तो यह सीधे पहुंचने के लिए लेयर 2 मैक क्षमता का अभाव है। इसे बिना शर्त पैकेट को अपने कॉन्फ़िगर किए गए डिफ़ॉल्ट गेटवे (निकटतम राउटर) पर अग्रेषित करना चाहिए।"}},
{type:"tf",diff:"hard",en:{q:"In a perfectly interconnected Full Mesh topology consisting of exactly 'n' computers, the strict mathematical formula calculating the precise number of physical cables required is n(n-1)/2.",opts:["True","False"],ans:0,exp:"True. In a full mesh, every single node is hardwired directly to every other node to guarantee absolute fault tolerance. The geometric combinatorial formula to calculate these point-to-point links is n(n-1)/2. So, a massive 10-node mesh requires 10(9)/2 = 45 separate physical cables, proving it is incredibly expensive and complex to scale."},hi:{q:"ठीक 'n' कंप्यूटरों वाले पूरी तरह से इंटरकनेक्टेड फुल मेश टोपोलॉजी (Full Mesh topology) में, आवश्यक भौतिक केबलों की सटीक संख्या की गणना करने वाला सख्त गणितीय सूत्र n(n-1)/2 है।",opts:["सही","गलत"],ans:0,exp:"सही। एक फुल मेश (Full Mesh) में, पूर्ण दोष सहिष्णुता की गारंटी देने के लिए हर एक नोड को हर दूसरे नोड से सीधे जोड़ा जाता है। इन पॉइंट-टू-पॉइंट लिंक की गणना करने का ज्यामितीय संयोजन सूत्र n(n-1)/2 है। इसलिए, 10-नोड मेश के लिए 10(9)/2 = 45 अलग-अलग भौतिक केबलों की आवश्यकता होती है।"}}
];
